{
  "name": "Calcolo Ravvedimento F24EP",
  "description": "Strumento professionale per il calcolo del Ravvedimento Operoso per Enti Pubblici (F24EP). Gestione calcolo sanzioni (sprint, breve, lungo), interessi legali composti e visualizzazione fac-simile F24EP con codici tributo aggiornati."
}

export interface InterestRate {
  start: string; // YYYY-MM-DD
  end: string;   // YYYY-MM-DD
  rate: number;  // Percentage
}

export interface TaxCode {
  code: string;
  description: string;
  sanctionCode: string; // The associated sanction code (e.g., 100E -> 896E)
}

export interface F24Row {
  id: string;
  taxCode: string;
  description: string;
  originalAmount: number;
  referenceMonth: string; // MM
  referenceYear: string;  // YYYY
}

export interface CalculationResult {
  rowId: string;
  daysLate: number;
  legalInterest: number;
  sanctionAmount: number;
  sanctionPercentage: number;
  totalTaxWithInterest: number; // For F24EP Tax Code column
  totalSanction: number;        // For F24EP Sanction Code column
  ravvedimentoType: string;
}

export enum RavvedimentoType {
  SPRINT = "Sprint (fino a 14 gg)",
  BREVE = "Breve (15-30 gg)",
  INTERMEDIO = "Intermedio (31-90 gg)",
  LUNGO = "Lungo (entro 1 anno)",
  LUNGHISSIMO = "Lunghissimo (entro 2 anni)",
  OLTRE = "Oltre 2 anni"
}

import { InterestRate, TaxCode } from './types';

// Historical Legal Interest Rates (Tasso Legale)
// Source: Italian Civil Code Art. 1284 updates
export const LEGAL_INTEREST_RATES: InterestRate[] = [
  { start: '2019-01-01', end: '2019-12-31', rate: 0.8 },
  { start: '2020-01-01', end: '2020-12-31', rate: 0.05 },
  { start: '2021-01-01', end: '2021-12-31', rate: 0.01 },
  { start: '2022-01-01', end: '2022-12-31', rate: 1.25 },
  { start: '2023-01-01', end: '2023-12-31', rate: 5.0 },
  { start: '2024-01-01', end: '2024-12-31', rate: 2.5 },
  { start: '2025-01-01', end: '2025-12-31', rate: 2.0 }, // Projected/Current
  { start: '2026-01-01', end: '2099-12-31', rate: 1.6 }, // Future projection from OCR
];

// Common F24EP Tax Codes
// Mapped to their respective Sanction Codes (Codes starting with 89xx usually)
export const TAX_CODES: TaxCode[] = [
  { code: '100E', description: 'IRPEF - Ritenute redditi lavoro dipendente', sanctionCode: '896E' },
  { code: '102E', description: 'IRPEF - Ritenute emolumenti arretrati', sanctionCode: '896E' },
  { code: '104E', description: 'IRPEF - Ritenute redditi lavoro autonomo', sanctionCode: '897E' },
  { code: '380E', description: 'IRAP - Versamento imposta', sanctionCode: '892E' },
  { code: '381E', description: 'Addizionale Regionale IRPEF', sanctionCode: '893E' },
  { code: '384E', description: 'Addizionale Comunale IRPEF (Saldo)', sanctionCode: '895E' },
  { code: '385E', description: 'Addizionale Comunale IRPEF (Acconto)', sanctionCode: '895E' },
  { code: '124E', description: 'Interessi Pagamento Dilazionato Add. Reg.', sanctionCode: '893E' }, // N/A usually, but keeping structure
  { code: '125E', description: 'Interessi Pagamento Dilazionato Add. Com.', sanctionCode: '895E' },
];

export const SANCTION_CODES_DESC: Record<string, string> = {
  '896E': 'Sanzione Ritenute Erariali (Dipendenti)',
  '897E': 'Sanzione Ritenute Lavoro Autonomo',
  '892E': 'Sanzione IRAP',
  '893E': 'Sanzione Addizionale Regionale',
  '895E': 'Sanzione Addizionale Comunale',
};

import { LEGAL_INTEREST_RATES, TAX_CODES } from '../constants';
import { CalculationResult, F24Row, RavvedimentoType } from '../types';

export const parseDate = (dateStr: string): Date => {
  return new Date(dateStr);
};

export const getDaysDiff = (start: Date, end: Date): number => {
  const diffTime = end.getTime() - start.getTime();
  return Math.ceil(diffTime / (1000 * 60 * 60 * 24));
};

export const calculateLegalInterest = (amount: number, dueDate: Date, payDate: Date): number => {
  let totalInterest = 0;
  let currentDate = new Date(dueDate);
  // Start from the day AFTER the due date
  currentDate.setDate(currentDate.getDate() + 1);

  while (currentDate <= payDate) {
    const dateStr = currentDate.toISOString().split('T')[0];

    // Find rate for this specific day
    const rateObj = LEGAL_INTEREST_RATES.find(r => dateStr >= r.start && dateStr <= r.end);
    const rate = rateObj ? rateObj.rate : 2.5; // Default fallback

    // Daily Interest = Amount * Rate% / 365
    // Note: OCR formula mentions / 36500 which is Rate / 100 / 365.
    totalInterest += (amount * rate) / 36500;

    // Move to next day
    currentDate.setDate(currentDate.getDate() + 1);
  }

  return totalInterest;
};

export const calculateSanction = (amount: number, daysLate: number, violationDate: Date): { percentage: number, amount: number, type: string } => {
  // Logic based on Art. 13 D.Lgs 472/97 and recent reforms (Sept 2024)
  // Simplified robust logic focusing on the "Riduzioni" normally applied.

  // Note: The OCR suggests 0.1% per day for the first 14 days (Sprint).
  // 1.5% for 15-30 days.
  // 1.67% for 31-90 days.
  // 3.75% for 91 days - 1 year.
  // 4.29% for 1-2 years.
  // 5.00% for > 2 years.

  let percentage = 0;
  let type = '';

  if (daysLate <= 14) {
    // Ravvedimento Sprint: 0.1% per day
    percentage = 0.1 * daysLate;
    type = RavvedimentoType.SPRINT;
  } else if (daysLate <= 30) {
    // Ravvedimento Breve: 1.5% (1/10 of 15%)
    percentage = 1.5;
    type = RavvedimentoType.BREVE;
  } else if (daysLate <= 90) {
    // Ravvedimento Intermedio: 1.67% (1/9 of 15%)
    percentage = 1.67;
    type = RavvedimentoType.INTERMEDIO;
  } else if (daysLate <= 365) {
    // Ravvedimento Lungo: 3.75% (1/8 of 30%)
    percentage = 3.75;
    type = RavvedimentoType.LUNGO;
  } else if (daysLate <= 730) {
    // Ravvedimento Lunghissimo: 4.29% (1/7 of 30%)
    percentage = 4.29;
    type = RavvedimentoType.LUNGHISSIMO;
  } else {
    // Oltre 2 anni: 5% (1/6 of 30%)
    percentage = 5.0;
    type = RavvedimentoType.OLTRE;
  }

  return {
    percentage: percentage,
    amount: (amount * percentage) / 100,
    type: type
  };
};

export const calculateRow = (row: F24Row, dueDateStr: string, payDateStr: string): CalculationResult => {
  const dueDate = parseDate(dueDateStr);
  const payDate = parseDate(payDateStr);

  const daysLate = getDaysDiff(dueDate, payDate);

  if (daysLate <= 0) {
    return {
      rowId: row.id,
      daysLate: 0,
      legalInterest: 0,
      sanctionAmount: 0,
      sanctionPercentage: 0,
      totalTaxWithInterest: row.originalAmount,
      totalSanction: 0,
      ravvedimentoType: 'In tempo'
    };
  }

  const interest = calculateLegalInterest(row.originalAmount, dueDate, payDate);
  const sanction = calculateSanction(row.originalAmount, daysLate, dueDate);

  return {
    rowId: row.id,
    daysLate: daysLate,
    legalInterest: interest,
    sanctionAmount: sanction.amount,
    sanctionPercentage: sanction.percentage,
    // F24EP Specific: Tax Code Amount = Original + Interest
    totalTaxWithInterest: row.originalAmount + interest,
    totalSanction: sanction.amount,
    ravvedimentoType: sanction.type
  };
};

export const formatCurrency = (val: number) => {
  return new Intl.NumberFormat('it-IT', { style: 'currency', currency: 'EUR' }).format(val);
};

export const getSanctionCode = (taxCode: string): string => {
  const found = TAX_CODES.find(t => t.code === taxCode);
  return found ? found.sanctionCode : '89xx';
};

