import React, { useState, useEffect, useMemo } from 'react';
import Header from './components/Header';
import F24Preview from './components/F24Preview';
import { TAX_CODES } from './constants';
import { F24Row, CalculationResult } from './types';
import { calculateRow, formatCurrency } from './utils/calculation';

function App() {
  const [originalDueDate, setOriginalDueDate] = useState<string>(new Date().toISOString().split('T')[0]);
  const [ravvedimentoDate, setRavvedimentoDate] = useState<string>(new Date().toISOString().split('T')[0]);

  const [rows, setRows] = useState<F24Row[]>([]);

  // New Row State
  const [selectedTaxCode, setSelectedTaxCode] = useState<string>(TAX_CODES[0].code);
  const [amount, setAmount] = useState<string>('');
  const [refMonth, setRefMonth] = useState<string>('01');
  const [refYear, setRefYear] = useState<string>(new Date().getFullYear().toString());

  const handleAddRow = () => {
    if (!amount || isNaN(parseFloat(amount))) return;

    const taxInfo = TAX_CODES.find(t => t.code === selectedTaxCode);
    const newRow: F24Row = {
      id: Math.random().toString(36).substr(2, 9),
      taxCode: selectedTaxCode,
      description: taxInfo?.description || '',
      originalAmount: parseFloat(amount),
      referenceMonth: refMonth,
      referenceYear: refYear
    };

    setRows([...rows, newRow]);
    setAmount('');
  };

  const handleRemoveRow = (id: string) => {
    setRows(rows.filter(r => r.id !== id));
  };

  // Calculate results whenever inputs change
  const results: CalculationResult[] = useMemo(() => {
    return rows.map(row => calculateRow(row, originalDueDate, ravvedimentoDate));
  }, [rows, originalDueDate, ravvedimentoDate]);

  return (
    <div className="min-h-screen bg-gray-50 pb-20">
      <Header />

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8 space-y-8">

        {/* Settings Card */}
        <section className="bg-white rounded-xl shadow-sm border border-gray-200 p-6">
          <h2 className="text-lg font-semibold text-gray-900 mb-4 flex items-center">
            <svg className="w-5 h-5 mr-2 text-blue-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 7V3m8 4V3m-9 8h10M5 21h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
            Date di Riferimento
          </h2>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Scadenza Originaria</label>
              <input 
                type="date" 
                value={originalDueDate}
                onChange={(e) => setOriginalDueDate(e.target.value)}
                className="w-full rounded-md border-gray-300 shadow-sm focus:border-blue-500 focus:ring-blue-500 sm:text-sm p-2 border"
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Data Ravvedimento (Pagamento)</label>
              <input 
                type="date" 
                value={ravvedimentoDate}
                onChange={(e) => setRavvedimentoDate(e.target.value)}
                className="w-full rounded-md border-gray-300 shadow-sm focus:border-blue-500 focus:ring-blue-500 sm:text-sm p-2 border"
              />
            </div>
          </div>
        </section>

        {/* Input Card */}
        <section className="bg-white rounded-xl shadow-sm border border-gray-200 p-6">
          <h2 className="text-lg font-semibold text-gray-900 mb-4 flex items-center">
            <svg className="w-5 h-5 mr-2 text-blue-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" /></svg>
            Inserimento Tributi
          </h2>

          <div className="grid grid-cols-1 md:grid-cols-12 gap-4 items-end">
            <div className="md:col-span-4">
              <label className="block text-sm font-medium text-gray-700 mb-1">Codice Tributo</label>
              <select 
                value={selectedTaxCode}
                onChange={(e) => setSelectedTaxCode(e.target.value)}
                className="w-full rounded-md border-gray-300 shadow-sm focus:border-blue-500 focus:ring-blue-500 sm:text-sm p-2 border"
              >
                {TAX_CODES.map(code => (
                  <option key={code.code} value={code.code}>{code.code} - {code.description}</option>
                ))}
              </select>
            </div>

            <div className="md:col-span-2">
              <label className="block text-sm font-medium text-gray-700 mb-1">Mese (MM)</label>
              <select 
                value={refMonth}
                onChange={(e) => setRefMonth(e.target.value)}
                className="w-full rounded-md border-gray-300 shadow-sm focus:border-blue-500 focus:ring-blue-500 sm:text-sm p-2 border"
              >
                {Array.from({length: 12}, (_, i) => String(i + 1).padStart(2, '0')).map(m => (
                  <option key={m} value={m}>{m}</option>
                ))}
              </select>
            </div>

            <div className="md:col-span-2">
              <label className="block text-sm font-medium text-gray-700 mb-1">Anno (AAAA)</label>
              <input 
                type="number"
                value={refYear}
                onChange={(e) => setRefYear(e.target.value)}
                className="w-full rounded-md border-gray-300 shadow-sm focus:border-blue-500 focus:ring-blue-500 sm:text-sm p-2 border"
              />
            </div>

            <div className="md:col-span-3">
              <label className="block text-sm font-medium text-gray-700 mb-1">Importo Omesso (€)</label>
              <input 
                type="number"
                step="0.01"
                value={amount}
                onChange={(e) => setAmount(e.target.value)}
                placeholder="0.00"
                className="w-full rounded-md border-gray-300 shadow-sm focus:border-blue-500 focus:ring-blue-500 sm:text-sm p-2 border"
              />
            </div>

            <div className="md:col-span-1">
              <button 
                onClick={handleAddRow}
                className="w-full bg-blue-600 text-white p-2 rounded-md hover:bg-blue-700 shadow transition-colors flex justify-center items-center"
              >
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6v6m0 0v6m0-6h6m-6 0H6" /></svg>
              </button>
            </div>
          </div>
        </section>

        {/* Calculation Table */}
        {rows.length > 0 && (
          <section className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
            <div className="px-6 py-4 border-b border-gray-200">
              <h2 className="text-lg font-semibold text-gray-900">Riepilogo Calcoli</h2>
            </div>
            <div className="overflow-x-auto">
              <table className="min-w-full divide-y divide-gray-200">
                <thead className="bg-gray-50">
                  <tr>
                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Codice</th>
                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Riferimento</th>
                    <th className="px-6 py-3 text-right text-xs font-medium text-gray-500 uppercase tracking-wider">Importo Orig.</th>
                    <th className="px-6 py-3 text-right text-xs font-medium text-gray-500 uppercase tracking-wider">Ritardo</th>
                    <th className="px-6 py-3 text-right text-xs font-medium text-gray-500 uppercase tracking-wider">Interessi (Calc.)</th>
                    <th className="px-6 py-3 text-right text-xs font-medium text-gray-500 uppercase tracking-wider">Sanzione</th>
                    <th className="px-6 py-3 text-right text-xs font-medium text-gray-500 uppercase tracking-wider">Totale Versamento</th>
                    <th className="px-6 py-3 text-center text-xs font-medium text-gray-500 uppercase tracking-wider">Azioni</th>
                  </tr>
                </thead>
                <tbody className="bg-white divide-y divide-gray-200">
                  {rows.map((row) => {
                    const result = results.find(r => r.rowId === row.id);
                    if(!result) return null;
                    return (
                      <tr key={row.id} className="hover:bg-gray-50">
                        <td className="px-6 py-4 whitespace-nowrap text-sm font-medium text-gray-900">{row.taxCode}</td>
                        <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">{row.referenceMonth}/{row.referenceYear}</td>
                        <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900 text-right">{formatCurrency(row.originalAmount)}</td>
                        <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500 text-right">
                          <span className="block">{result.daysLate} gg</span>
                          <span className="text-xs text-gray-400">{result.ravvedimentoType}</span>
                        </td>
                        <td className="px-6 py-4 whitespace-nowrap text-sm text-orange-600 font-medium text-right">
                          {formatCurrency(result.legalInterest)}
                        </td>
                        <td className="px-6 py-4 whitespace-nowrap text-sm text-red-600 font-medium text-right">
                          <span className="block">{formatCurrency(result.sanctionAmount)}</span>
                          <span className="text-xs text-gray-400">({result.sanctionPercentage.toFixed(2)}%)</span>
                        </td>
                        <td className="px-6 py-4 whitespace-nowrap text-sm font-bold text-blue-900 text-right">
                          {formatCurrency(result.totalTaxWithInterest + result.totalSanction)}
                        </td>
                        <td className="px-6 py-4 whitespace-nowrap text-center">
                          <button onClick={() => handleRemoveRow(row.id)} className="text-red-600 hover:text-red-900">
                            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                          </button>
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
          </section>
        )}

        <F24Preview rows={rows} results={results} />

      </main>
    </div>
  );
}

export default App;

import { LEGAL_INTEREST_RATES, TAX_CODES } from '../constants';
import { CalculationResult, F24Row, RavvedimentoType } from '../types';

export const parseDate = (dateStr: string): Date => {
  return new Date(dateStr);
};

export const getDaysDiff = (start: Date, end: Date): number => {
  const diffTime = end.getTime() - start.getTime();
  return Math.ceil(diffTime / (1000 * 60 * 60 * 24));
};

export const calculateLegalInterest = (amount: number, dueDate: Date, payDate: Date): number => {
  let totalInterest = 0;
  let currentDate = new Date(dueDate);
  // Start from the day AFTER the due date
  currentDate.setDate(currentDate.getDate() + 1);

  while (currentDate <= payDate) {
    const dateStr = currentDate.toISOString().split('T')[0];

    // Find rate for this specific day
    // Assumes constants are sorted or cover the range. Fallback 2.5 is just a safety.
    const rateObj = LEGAL_INTEREST_RATES.find(r => dateStr >= r.start && dateStr <= r.end);
    const rate = rateObj ? rateObj.rate : 2.5; 

    // Daily Interest = Amount * Rate% / 365
    // Note: Standard financial year 365 is used for simplification unless strict 366 required.
    totalInterest += (amount * rate) / 36500;

    // Move to next day
    currentDate.setDate(currentDate.getDate() + 1);
  }

  return totalInterest;
};

export const calculateSanction = (amount: number, daysLate: number, violationDate: Date): { percentage: number, amount: number, type: string } => {
  // Logic updated based on "Riforma Sanzioni" (D.Lgs 87/2024) effective 01/09/2024.
  // Base Sanction for omitted payment: 25% (was 30%).
  // Reduced Base for delays <= 90 days: 12.5% (was 15%).

  let percentage = 0;
  let type = '';

  if (daysLate <= 14) {
    // Ravvedimento Sprint
    // Reduced to 1/15 per day of the "Breve" amount (1/10 of Min).
    // Min (<90 days) = 12.5%.
    // Breve = 1.25%.
    // Sprint Daily = 1.25% / 15 = 0.0833...%
    percentage = (1.25 / 15) * daysLate;
    type = RavvedimentoType.SPRINT;
  } else if (daysLate <= 30) {
    // Ravvedimento Breve (Art. 13 c. 1 lett. a)
    // 1/10 of Minimum (12.5%)
    percentage = 1.25;
    type = RavvedimentoType.BREVE;
  } else if (daysLate <= 90) {
    // Ravvedimento Intermedio (Art. 13 c. 1 lett. a-bis)
    // 1/9 of Minimum (12.5%) -> ~1.39%
    percentage = 12.5 / 9;
    type = RavvedimentoType.INTERMEDIO;
  } else if (daysLate <= 365) {
    // Ravvedimento Lungo (Art. 13 c. 1 lett. b)
    // 1/8 of Minimum.
    // Note: For delays > 90 days, the special 12.5% base no longer applies. Base reverts to 25%.
    percentage = 25 / 8; // 3.125%
    type = RavvedimentoType.LUNGO;
  } else if (daysLate <= 730) {
    // Ravvedimento Lunghissimo (Art. 13 c. 1 lett. b-bis)
    // 1/7 of Minimum (25%)
    percentage = 25 / 7; // ~3.57%
    type = RavvedimentoType.LUNGHISSIMO;
  } else {
    // Oltre 2 anni (Art. 13 c. 1 lett. b-ter)
    // 1/6 of Minimum (25%)
    percentage = 25 / 6; // ~4.17%
    type = RavvedimentoType.OLTRE;
  }

  return {
    percentage: percentage,
    amount: (amount * percentage) / 100,
    type: type
  };
};

export const calculateRow = (row: F24Row, dueDateStr: string, payDateStr: string): CalculationResult => {
  const dueDate = parseDate(dueDateStr);
  const payDate = parseDate(payDateStr);

  const daysLate = getDaysDiff(dueDate, payDate);

  if (daysLate <= 0) {
    return {
      rowId: row.id,
      daysLate: 0,
      legalInterest: 0,
      sanctionAmount: 0,
      sanctionPercentage: 0,
      totalTaxWithInterest: row.originalAmount,
      totalSanction: 0,
      ravvedimentoType: 'In tempo'
    };
  }

  const interest = calculateLegalInterest(row.originalAmount, dueDate, payDate);
  const sanction = calculateSanction(row.originalAmount, daysLate, dueDate);

  return {
    rowId: row.id,
    daysLate: daysLate,
    legalInterest: interest,
    sanctionAmount: sanction.amount,
    sanctionPercentage: sanction.percentage,
    // F24EP Specific: Tax Code Amount = Original + Interest (Principio del Cumulo)
    totalTaxWithInterest: row.originalAmount + interest,
    totalSanction: sanction.amount,
    ravvedimentoType: sanction.type
  };
};

export const formatCurrency = (val: number) => {
  return new Intl.NumberFormat('it-IT', { style: 'currency', currency: 'EUR' }).format(val);
};

export const getSanctionCode = (taxCode: string): string => {
  const found = TAX_CODES.find(t => t.code === taxCode);
  return found ? found.sanctionCode : '89xx';
};

