import React, { useState, useEffect, useMemo } from 'react';
import Header from './components/Header';
import Footer from './components/Footer';
import F24Preview from './components/F24Preview';
import { TAX_CODES } from './constants';
import { F24Row, CalculationResult, InterestPeriod } from './types';
import { calculateRow, formatCurrency } from './utils/calculation';

function App() {
  const [originalDueDate, setOriginalDueDate] = useState<string>(new Date().toISOString().split('T')[0]);
  const [ravvedimentoDate, setRavvedimentoDate] = useState<string>(new Date().toISOString().split('T')[0]);

  const [rows, setRows] = useState<F24Row[]>([]);

  // New Row State
  const [selectedTaxCode, setSelectedTaxCode] = useState<string>(TAX_CODES[0].code);
  const [amount, setAmount] = useState<string>('');
  const [refMonth, setRefMonth] = useState<string>('01');
  const [refYear, setRefYear] = useState<string>(new Date().getFullYear().toString());
  const [locationCode, setLocationCode] = useState<string>('');

  // Dark Mode State
  const [darkMode, setDarkMode] = useState(false);

  // Modal State
  const [interestModalOpen, setInterestModalOpen] = useState(false);
  const [selectedInterestDetails, setSelectedInterestDetails] = useState<{code: string, amount: number, details: InterestPeriod[]} | null>(null);

  useEffect(() => {
    const stored = localStorage.getItem('color-theme');
    if (stored === 'dark' || (!stored && window.matchMedia('(prefers-color-scheme: dark)').matches)) {
      setDarkMode(true);
    } else {
      setDarkMode(false);
    }
  }, []);

  useEffect(() => {
    if (darkMode) {
      document.documentElement.classList.add('dark');
      localStorage.setItem('color-theme', 'dark');
    } else {
      document.documentElement.classList.remove('dark');
      localStorage.setItem('color-theme', 'light');
    }
  }, [darkMode]);

  // Reset location code when tax code changes
  useEffect(() => {
    setLocationCode('');
  }, [selectedTaxCode]);

  const toggleDarkMode = () => setDarkMode(!darkMode);

  const selectedTaxInfo = useMemo(() => TAX_CODES.find(t => t.code === selectedTaxCode), [selectedTaxCode]);

  const handleAddRow = () => {
    if (!amount || isNaN(parseFloat(amount))) return;
    if (selectedTaxInfo?.requiresLocationCode && !locationCode) {
      alert(`Il campo "${selectedTaxInfo.locationCodeLabel}" è obbligatorio per questo codice tributo.`);
      return;
    }

    const newRow: F24Row = {
      id: Math.random().toString(36).substr(2, 9),
      taxCode: selectedTaxCode,
      description: selectedTaxInfo?.description || '',
      originalAmount: parseFloat(amount),
      referenceMonth: refMonth,
      referenceYear: refYear,
      section: selectedTaxInfo?.section || 'ERARIO',
      locationCode: locationCode.toUpperCase()
    };

    setRows([...rows, newRow]);
    setAmount('');
    setLocationCode('');
  };

  const handleRemoveRow = (id: string) => {
    setRows(rows.filter(r => r.id !== id));
  };

  const openInterestModal = (code: string, originalAmount: number, details: InterestPeriod[]) => {
    setSelectedInterestDetails({
      code,
      amount: originalAmount,
      details
    });
    setInterestModalOpen(true);
  };

  const closeInterestModal = () => {
    setInterestModalOpen(false);
    setSelectedInterestDetails(null);
  };

  const results: CalculationResult[] = useMemo(() => {
    return rows.map(row => calculateRow(row, originalDueDate, ravvedimentoDate));
  }, [rows, originalDueDate, ravvedimentoDate]);

  return (
    <>
      <Header darkMode={darkMode} toggleDarkMode={toggleDarkMode} />

      <main className="flex-grow max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-10 space-y-8 w-full relative">

        {/* Info Banner (Chapter 5.2 - Transparency) */}
        <div className="bg-blue-50 dark:bg-blue-900/20 border-l-4 border-italia-blue p-4 rounded-r shadow-sm">
          <div className="flex">
            <div className="flex-shrink-0">
              <svg className="h-5 w-5 text-italia-blue" viewBox="0 0 20 20" fill="currentColor">
                <path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7-4a1 1 0 11-2 0 1 1 0 012 0zM9 9a1 1 0 000 2v3a1 1 0 001 1h1a1 1 0 100-2v-3a1 1 0 00-1-1H9z" clipRule="evenodd" />
              </svg>
            </div>
            <div className="ml-3">
              <p className="text-sm text-blue-900 dark:text-blue-100">
                <strong>Nota Informativa:</strong> Questo strumento supporta il calcolo del ravvedimento operoso secondo la normativa vigente (inclusa Riforma D.Lgs 87/2024). I calcoli sono da intendersi come supporto operativo e non sostituiscono le verifiche ufficiali.
              </p>
            </div>
          </div>
        </div>

        {/* Settings Card */}
        <section className="bg-white dark:bg-gray-800 rounded shadow-md border-t-4 border-italia-blue p-6 transition-colors duration-200">
          <h2 className="text-xl font-bold text-italia-dark dark:text-white mb-6 border-b border-gray-200 dark:border-gray-700 pb-2">
            1. Date di Riferimento
          </h2>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            <div>
              <label className="block text-sm font-semibold text-gray-700 dark:text-gray-300 mb-2">Scadenza Originaria</label>
              <input 
                type="date" 
                value={originalDueDate}
                onChange={(e) => setOriginalDueDate(e.target.value)}
                className="w-full rounded border-2 border-gray-300 dark:border-gray-600 dark:bg-gray-700 dark:text-white shadow-sm focus:border-italia-blue focus:ring-0 sm:text-base p-2.5 transition-colors"
              />
            </div>
            <div>
              <label className="block text-sm font-semibold text-gray-700 dark:text-gray-300 mb-2">Data Ravvedimento (Pagamento)</label>
              <input 
                type="date" 
                value={ravvedimentoDate}
                onChange={(e) => setRavvedimentoDate(e.target.value)}
                className="w-full rounded border-2 border-gray-300 dark:border-gray-600 dark:bg-gray-700 dark:text-white shadow-sm focus:border-italia-blue focus:ring-0 sm:text-base p-2.5 transition-colors"
              />
            </div>
          </div>
        </section>

        {/* Input Card */}
        <section className="bg-white dark:bg-gray-800 rounded shadow-md border-t-4 border-italia-blue p-6 transition-colors duration-200">
           <h2 className="text-xl font-bold text-italia-dark dark:text-white mb-6 border-b border-gray-200 dark:border-gray-700 pb-2">
            2. Inserimento Tributi
          </h2>

          <div className="grid grid-cols-1 md:grid-cols-12 gap-6 items-end">
            <div className="md:col-span-4">
              <label className="block text-sm font-semibold text-gray-700 dark:text-gray-300 mb-2">Codice Tributo</label>
              <select 
                value={selectedTaxCode}
                onChange={(e) => setSelectedTaxCode(e.target.value)}
                className="w-full rounded border-2 border-gray-300 dark:border-gray-600 dark:bg-gray-700 dark:text-white shadow-sm focus:border-italia-blue focus:ring-0 sm:text-base p-2.5 transition-colors"
              >
                {TAX_CODES.map(code => (
                  <option key={code.code} value={code.code}>{code.code} - {code.description}</option>
                ))}
              </select>
            </div>

            {/* Conditional Input for Region/Municipality Code */}
            {selectedTaxInfo?.requiresLocationCode ? (
              <div className="md:col-span-2">
                <label className="block text-sm font-semibold text-gray-700 dark:text-gray-300 mb-2 truncate" title={selectedTaxInfo.locationCodeLabel}>
                  {selectedTaxInfo.locationCodeLabel}
                </label>
                <input 
                  type="text"
                  value={locationCode}
                  onChange={(e) => setLocationCode(e.target.value)}
                  maxLength={selectedTaxInfo.locationCodeMaxLength}
                  className="w-full rounded border-2 border-orange-300 dark:border-orange-500 dark:bg-gray-700 dark:text-white shadow-sm focus:border-italia-blue focus:ring-0 sm:text-base p-2.5 transition-colors uppercase"
                  placeholder={selectedTaxInfo.locationCodeMaxLength === 2 ? "es. 09" : "es. H501"}
                />
              </div>
            ) : (
              // Spacer to keep layout consistent if no code needed
              <div className="md:col-span-2"></div> 
            )}

            <div className="md:col-span-1">
              <label className="block text-sm font-semibold text-gray-700 dark:text-gray-300 mb-2">Mese</label>
              <select 
                value={refMonth}
                onChange={(e) => setRefMonth(e.target.value)}
                className="w-full rounded border-2 border-gray-300 dark:border-gray-600 dark:bg-gray-700 dark:text-white shadow-sm focus:border-italia-blue focus:ring-0 sm:text-base p-2.5 transition-colors"
              >
                {Array.from({length: 12}, (_, i) => String(i + 1).padStart(2, '0')).map(m => (
                  <option key={m} value={m}>{m}</option>
                ))}
              </select>
            </div>

            <div className="md:col-span-2">
              <label className="block text-sm font-semibold text-gray-700 dark:text-gray-300 mb-2">Anno</label>
              <input 
                type="number"
                value={refYear}
                onChange={(e) => setRefYear(e.target.value)}
                className="w-full rounded border-2 border-gray-300 dark:border-gray-600 dark:bg-gray-700 dark:text-white shadow-sm focus:border-italia-blue focus:ring-0 sm:text-base p-2.5 transition-colors"
              />
            </div>

            <div className="md:col-span-2">
              <label className="block text-sm font-semibold text-gray-700 dark:text-gray-300 mb-2">Importo (€)</label>
              <input 
                type="number"
                step="0.01"
                value={amount}
                onChange={(e) => setAmount(e.target.value)}
                placeholder="0.00"
                className="w-full rounded border-2 border-gray-300 dark:border-gray-600 dark:bg-gray-700 dark:text-white shadow-sm focus:border-italia-blue focus:ring-0 sm:text-base p-2.5 transition-colors placeholder-gray-400 dark:placeholder-gray-400"
              />
            </div>

            <div className="md:col-span-1">
              <button 
                onClick={handleAddRow}
                className="w-full bg-italia-blue text-white py-3 px-4 rounded font-bold hover:bg-blue-700 dark:hover:bg-blue-600 shadow-md transition-all transform hover:scale-105 flex justify-center items-center"
                title="Aggiungi Tributo"
              >
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6v6m0 0v6m0-6h6m-6 0H6" /></svg>
              </button>
            </div>
          </div>
        </section>

        {/* Calculation Table */}
        {rows.length > 0 && (
          <section className="bg-white dark:bg-gray-800 rounded shadow-md border-t-4 border-italia-blue overflow-hidden transition-colors duration-200">
             <div className="px-6 py-4 border-b border-gray-200 dark:border-gray-700">
              <h2 className="text-xl font-bold text-italia-dark dark:text-white">Riepilogo Calcoli</h2>
            </div>
            <div className="overflow-x-auto">
              <table className="min-w-full divide-y divide-gray-200 dark:divide-gray-700">
                <thead className="bg-gray-100 dark:bg-gray-900">
                  <tr>
                    <th className="px-6 py-3 text-left text-xs font-bold text-gray-600 dark:text-gray-300 uppercase tracking-wider">Codice</th>
                    <th className="px-6 py-3 text-left text-xs font-bold text-gray-600 dark:text-gray-300 uppercase tracking-wider">Sezione/Ente</th>
                    <th className="px-6 py-3 text-left text-xs font-bold text-gray-600 dark:text-gray-300 uppercase tracking-wider">Riferimento</th>
                    <th className="px-6 py-3 text-right text-xs font-bold text-gray-600 dark:text-gray-300 uppercase tracking-wider">Importo Orig.</th>
                    <th className="px-6 py-3 text-right text-xs font-bold text-gray-600 dark:text-gray-300 uppercase tracking-wider">Ritardo</th>
                    <th className="px-6 py-3 text-right text-xs font-bold text-gray-600 dark:text-gray-300 uppercase tracking-wider">Interessi (Calc.)</th>
                    <th className="px-6 py-3 text-right text-xs font-bold text-gray-600 dark:text-gray-300 uppercase tracking-wider">Sanzione</th>
                    <th className="px-6 py-3 text-right text-xs font-bold text-gray-600 dark:text-gray-300 uppercase tracking-wider">Totale Versamento</th>
                    <th className="px-6 py-3 text-center text-xs font-bold text-gray-600 dark:text-gray-300 uppercase tracking-wider">Azioni</th>
                  </tr>
                </thead>
                <tbody className="bg-white dark:bg-gray-800 divide-y divide-gray-200 dark:divide-gray-700">
                  {rows.map((row) => {
                    const result = results.find(r => r.rowId === row.id);
                    if(!result) return null;
                    return (
                      <tr key={row.id} className="hover:bg-blue-50 dark:hover:bg-gray-700/50 transition-colors">
                        <td className="px-6 py-4 whitespace-nowrap text-sm font-semibold text-gray-900 dark:text-gray-100">{row.taxCode}</td>
                        <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-600 dark:text-gray-400">
                          <div className="font-semibold text-xs uppercase">{row.section}</div>
                          {row.locationCode && <div className="text-xs font-mono bg-gray-100 dark:bg-gray-700 px-1 rounded inline-block mt-1">{row.locationCode}</div>}
                        </td>
                        <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-600 dark:text-gray-400">{row.referenceMonth}/{row.referenceYear}</td>
                        <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900 dark:text-gray-100 text-right font-mono">{formatCurrency(row.originalAmount)}</td>
                        <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-600 dark:text-gray-400 text-right">
                          <span className="block font-semibold">{result.daysLate} gg</span>
                          <span className="text-xs text-gray-500 dark:text-gray-500">{result.ravvedimentoType}</span>
                        </td>
                        <td className="px-6 py-4 whitespace-nowrap text-sm text-orange-700 dark:text-orange-400 font-bold text-right font-mono">
                          <div className="flex items-center justify-end gap-2">
                            <span>{formatCurrency(result.legalInterest)}</span>
                            <button 
                              onClick={() => openInterestModal(row.taxCode, row.originalAmount, result.interestDetails)}
                              className="text-italia-blue dark:text-blue-400 hover:text-blue-800 dark:hover:text-blue-200 focus:outline-none focus:text-blue-800"
                              title="Visualizza dettaglio calcolo interessi"
                            >
                              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                                <path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7-4a1 1 0 11-2 0 1 1 0 012 0zM9 9a1 1 0 000 2v3a1 1 0 001 1h1a1 1 0 100-2v-3a1 1 0 00-1-1H9z" clipRule="evenodd" />
                              </svg>
                            </button>
                          </div>
                          {result.legalInterest > 0 && result.legalInterest < 1.03 && (
                            <div className="inline-flex items-center px-2 py-0.5 rounded text-[10px] font-bold bg-orange-100 text-orange-800 mt-1">
                              &lt; Min
                            </div>
                          )}
                        </td>
                        <td className="px-6 py-4 whitespace-nowrap text-sm text-red-700 dark:text-red-400 font-bold text-right font-mono">
                          <span className="block">{formatCurrency(result.sanctionAmount)}</span>
                          <span className="text-xs text-gray-500 dark:text-gray-500 font-normal">({result.sanctionPercentage.toFixed(2)}%)</span>
                        </td>
                        <td className="px-6 py-4 whitespace-nowrap text-sm font-bold text-italia-blue dark:text-blue-300 text-right font-mono text-base">
                          {formatCurrency(result.totalTaxWithInterest + result.totalSanction)}
                        </td>
                        <td className="px-6 py-4 whitespace-nowrap text-center">
                          <button onClick={() => handleRemoveRow(row.id)} className="text-red-600 hover:text-red-900 dark:text-red-400 dark:hover:text-red-300 transition-colors">
                            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                          </button>
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
            <div className="px-6 py-4 bg-gray-50 dark:bg-gray-700/50 border-t border-gray-200 dark:border-gray-700">
               <p className="text-xs text-gray-500 dark:text-gray-400 italic">
                 Nota: Se l'interesse calcolato è inferiore a € 1,03, potrebbe non essere dovuto in quanto inferiore al minimale di versamento.
               </p>
            </div>
          </section>
        )}

        <F24Preview rows={rows} results={results} />

      </main>

      {/* Interest Details Modal */}
      {interestModalOpen && selectedInterestDetails && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black bg-opacity-50 p-4">
          <div className="bg-white dark:bg-gray-800 rounded-lg shadow-xl max-w-2xl w-full flex flex-col max-h-[90vh] border-t-4 border-italia-blue">
            <div className="px-6 py-4 border-b border-gray-200 dark:border-gray-700 flex justify-between items-center bg-gray-50 dark:bg-gray-900 rounded-t-lg">
              <div>
                <h3 className="text-lg font-bold text-italia-dark dark:text-white">Dettaglio Calcolo Interessi Legali</h3>
                <p className="text-sm text-gray-500 dark:text-gray-400">Codice Tributo: <span className="font-mono font-bold">{selectedInterestDetails.code}</span> - Capitale: {formatCurrency(selectedInterestDetails.amount)}</p>
              </div>
              <button onClick={closeInterestModal} className="text-gray-400 hover:text-gray-600 dark:hover:text-gray-300 transition-colors">
                <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                </svg>
              </button>
            </div>
            <div className="p-6 overflow-y-auto">
              <p className="text-sm text-gray-600 dark:text-gray-300 mb-4">
                Gli interessi legali sono calcolati pro-rata temporis in base al tasso legale vigente per ciascun periodo di ritardo.
              </p>
              <div className="border rounded-md overflow-hidden border-gray-200 dark:border-gray-700">
                <table className="min-w-full divide-y divide-gray-200 dark:divide-gray-700">
                  <thead className="bg-gray-100 dark:bg-gray-900">
                    <tr>
                      <th className="px-4 py-3 text-left text-xs font-bold text-gray-600 dark:text-gray-300 uppercase">Periodo</th>
                      <th className="px-4 py-3 text-center text-xs font-bold text-gray-600 dark:text-gray-300 uppercase">Giorni</th>
                      <th className="px-4 py-3 text-center text-xs font-bold text-gray-600 dark:text-gray-300 uppercase">Tasso</th>
                      <th className="px-4 py-3 text-right text-xs font-bold text-gray-600 dark:text-gray-300 uppercase">Importo</th>
                    </tr>
                  </thead>
                  <tbody className="bg-white dark:bg-gray-800 divide-y divide-gray-200 dark:divide-gray-700">
                    {selectedInterestDetails.details.length === 0 ? (
                      <tr>
                        <td colSpan={4} className="px-4 py-4 text-center text-sm text-gray-500">Nessun interesse maturato.</td>
                      </tr>
                    ) : (
                      selectedInterestDetails.details.map((detail, idx) => (
                        <tr key={idx} className="hover:bg-gray-50 dark:hover:bg-gray-700/50">
                          <td className="px-4 py-3 text-sm text-gray-700 dark:text-gray-300">
                            Dal {new Date(detail.startDate).toLocaleDateString('it-IT')} al {new Date(detail.endDate).toLocaleDateString('it-IT')}
                          </td>
                          <td className="px-4 py-3 text-center text-sm font-mono text-gray-700 dark:text-gray-300">{detail.days}</td>
                          <td className="px-4 py-3 text-center text-sm font-mono text-gray-700 dark:text-gray-300">{detail.rate.toFixed(2)}%</td>
                          <td className="px-4 py-3 text-right text-sm font-mono font-bold text-italia-blue dark:text-blue-400">
                            {formatCurrency(detail.amount)}
                          </td>
                        </tr>
                      ))
                    )}
                  </tbody>
                  <tfoot className="bg-gray-50 dark:bg-gray-900 font-bold border-t border-gray-200 dark:border-gray-700">
                    <tr>
                      <td colSpan={3} className="px-4 py-3 text-right text-sm text-gray-800 dark:text-gray-200 uppercase">Totale Interessi</td>
                      <td className="px-4 py-3 text-right text-sm font-mono text-italia-blue dark:text-blue-400">
                        {formatCurrency(selectedInterestDetails.details.reduce((sum, d) => sum + d.amount, 0))}
                      </td>
                    </tr>
                  </tfoot>
                </table>
              </div>
            </div>
            <div className="px-6 py-4 border-t border-gray-200 dark:border-gray-700 bg-gray-50 dark:bg-gray-900 rounded-b-lg flex justify-end">
              <button 
                onClick={closeInterestModal}
                className="bg-italia-blue text-white px-4 py-2 rounded text-sm font-semibold hover:bg-blue-700 transition-colors shadow-sm"
              >
                Chiudi
              </button>
            </div>
          </div>
        </div>
      )}

      <Footer />
    </>
  );
}

export default App;

import React from 'react';
import { CalculationResult, F24Row } from '../types';
import { getSanctionCode, formatCurrency } from '../utils/calculation';
import { SANCTION_CODES_DESC, SANCTION_SECTIONS } from '../constants';
import jsPDF from 'jspdf';
import autoTable from 'jspdf-autotable';

interface Props {
  rows: F24Row[];
  results: CalculationResult[];
}

interface AggregatedSanction {
  code: string;
  description: string;
  referenceYear: string;
  referenceMonth: string;
  amount: number;
  section: string;
  locationCode?: string;
}

const F24Preview: React.FC<Props> = ({ rows, results }) => {
  if (rows.length === 0) return null;

  // Group sanctions by Code + Year + Section + LocationCode
  // NOTE: Sanctions for Regional/Local taxes also require the region/municipality code.
  const aggregatedSanctions: Record<string, AggregatedSanction> = {};

  rows.forEach((row) => {
    const result = results.find((r) => r.rowId === row.id);
    if (!result || result.totalSanction <= 0) return;

    const sCode = getSanctionCode(row.taxCode);
    const sSection = SANCTION_SECTIONS[sCode] || row.section; // Default to row section if not mapped
    const locCode = row.locationCode || '';

    // Grouping Key must differentiate different location codes (e.g., sanction for Rome vs Milan)
    const key = `${sCode}_${row.referenceYear}_${locCode}`; 

    if (aggregatedSanctions[key]) {
      aggregatedSanctions[key].amount += result.totalSanction;
    } else {
      aggregatedSanctions[key] = {
        code: sCode,
        description: SANCTION_CODES_DESC[sCode] || 'Sanzione',
        referenceYear: row.referenceYear,
        referenceMonth: row.referenceMonth, // We keep the first month encountered as Ref A base
        amount: result.totalSanction,
        section: sSection,
        locationCode: row.locationCode // Keep the location code of the tax for the sanction
      };
    }
  });

  const sanctionRows = Object.values(aggregatedSanctions);

  const handleExportCSV = () => {
    const headers = [
      "Sezione",
      "Codice Tributo",
      "Codice",
      "Estremi identificativi",
      "Riferimento A",
      "Riferimento B",
      "Importi a debito versati"
    ];

    const csvRows = [];
    csvRows.push(headers.join(";")); // Semicolon for Italian Excel compatibility

    // 1. Tax Rows
    rows.forEach(row => {
      const result = results.find(r => r.rowId === row.id);
      if (!result) return;

      const line = [
        row.section,
        row.taxCode,
        row.locationCode || "",
        `"${row.description} (Incl. interessi € ${result.legalInterest.toFixed(2).replace('.', ',')})"`,
        `${row.referenceMonth} ${row.referenceYear}`,
        row.referenceYear,
        result.totalTaxWithInterest.toFixed(2).replace('.', ',')
      ];
      csvRows.push(line.join(";"));
    });

    // 2. Sanction Rows
    sanctionRows.forEach(sanction => {
      const line = [
        sanction.section,
        sanction.code,
        sanction.locationCode || "",
        `"${sanction.description}"`,
        `${sanction.referenceMonth} ${sanction.referenceYear}`,
        sanction.referenceYear,
        sanction.amount.toFixed(2).replace('.', ',')
      ];
      csvRows.push(line.join(";"));
    });

    // Total Row
    const totalAmount = results.reduce((acc, curr) => acc + curr.totalTaxWithInterest + curr.totalSanction, 0);
    csvRows.push([
        "", "", "", "TOTALE GENERALE", "", "", totalAmount.toFixed(2).replace('.', ',')
    ].join(";"));

    const csvString = csvRows.join("\n");
    const blob = new Blob([csvString], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.setAttribute("href", url);
    link.setAttribute("download", `F24EP_Ravvedimento_${new Date().toISOString().split('T')[0]}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleExportPDF = () => {
    // Initialize PDF in Landscape mode (F24EP is wide)
    const doc = new jsPDF({ orientation: 'landscape', unit: 'mm', format: 'a4' });

    // Header
    doc.setFontSize(16);
    doc.setTextColor(0, 102, 204); // Italia Blue
    doc.text("MODELLO DI VERSAMENTO F24 ENTI PUBBLICI", 14, 15);

    doc.setFontSize(10);
    doc.setTextColor(100);
    doc.text(`Prospetto di Liquidazione - Ravvedimento Operoso generato il ${new Date().toLocaleDateString('it-IT')}`, 14, 22);

    // Prepare Table Data
    const tableBody = [];

    // 1. Tax Rows
    rows.forEach(row => {
      const result = results.find(r => r.rowId === row.id);
      if (!result) return;

      tableBody.push([
        row.section,
        row.taxCode,
        row.locationCode || "",
        `${row.description}\n(Capitale: ${formatCurrency(row.originalAmount)} + Int: ${formatCurrency(result.legalInterest)})`,
        `${row.referenceMonth} ${row.referenceYear}`,
        row.referenceYear,
        formatCurrency(result.totalTaxWithInterest),
        "" // Credit column empty
      ]);
    });

    // 2. Sanction Rows
    sanctionRows.forEach(sanction => {
      tableBody.push([
        sanction.section,
        sanction.code,
        sanction.locationCode || "",
        sanction.description,
        `${sanction.referenceMonth} ${sanction.referenceYear}`,
        sanction.referenceYear,
        formatCurrency(sanction.amount),
        "" // Credit column empty
      ]);
    });

    // Total Row
    const totalAmount = results.reduce((acc, curr) => acc + curr.totalTaxWithInterest + curr.totalSanction, 0);
    tableBody.push([
      { content: 'TOTALE GENERALE', colSpan: 6, styles: { halign: 'right', fontStyle: 'bold' } },
      { content: formatCurrency(totalAmount), styles: { fontStyle: 'bold' } },
      ""
    ]);

    // Generate Table
    autoTable(doc, {
      startY: 30,
      head: [[
        "SEZIONE", 
        "CODICE\nTRIBUTO", 
        "CODICE", 
        "ESTREMI IDENTIFICATIVI", 
        "RIFERIMENTO A\n(mm/aaaa)", 
        "RIFERIMENTO B\n(aaaa)", 
        "IMPORTI A DEBITO\nVERSATI",
        "IMPORTI A CREDITO\nCOMPENSATI"
      ]],
      body: tableBody,
      theme: 'grid',
      headStyles: {
        fillColor: [0, 102, 204], // Italia Blue
        textColor: 255,
        fontSize: 8,
        halign: 'center',
        valign: 'middle',
        lineWidth: 0.1
      },
      bodyStyles: {
        fontSize: 9,
        valign: 'middle',
        textColor: 50
      },
      columnStyles: {
        0: { halign: 'center', cellWidth: 20 }, // Sezione
        1: { halign: 'center', cellWidth: 20 }, // Codice Tributo
        2: { halign: 'center', cellWidth: 20 }, // Codice (increased for visibility)
        3: { cellWidth: 'auto' },               // Estremi
        4: { halign: 'center', cellWidth: 25 }, // Rif A
        5: { halign: 'center', cellWidth: 20 }, // Rif B
        6: { halign: 'right', cellWidth: 30 },  // Debito
        7: { halign: 'right', cellWidth: 30 },  // Credito
      },
      footStyles: {
        fillColor: [240, 241, 242],
        textColor: 0,
        fontStyle: 'bold'
      }
    });

    // Footer / Disclaimer
    const finalY = (doc as any).lastAutoTable.finalY || 30;
    doc.setFontSize(8);
    doc.setTextColor(150);
    doc.text("Fac-simile non valido ai fini fiscali. Utilizzare i dati riportati per la compilazione del modello F24EP ufficiale.", 14, finalY + 10);

    doc.save(`F24EP_FacSimile_${new Date().toISOString().split('T')[0]}.pdf`);
  };

  return (
    <div className="bg-white dark:bg-gray-800 p-8 rounded shadow-md border-t-4 border-italia-blue mt-8 transition-colors duration-200">
      <div className="mb-6 border-b border-gray-200 dark:border-gray-700 pb-4 flex justify-between items-end">
        <div>
          <h2 className="text-xl font-bold text-italia-dark dark:text-white">
            Prospetto Versamento F24EP
          </h2>
          <p className="text-sm text-gray-500 dark:text-gray-400 mt-1">
            Anteprima dei codici da utilizzare nel modello F24 Enti Pubblici
          </p>
        </div>
        <div className="flex items-center gap-3">
             <button 
                onClick={handleExportCSV}
                className="bg-white dark:bg-transparent text-gray-600 dark:text-gray-300 border border-gray-300 dark:border-gray-500 hover:bg-gray-50 dark:hover:bg-gray-700 font-semibold py-1 px-3 rounded text-sm transition-colors flex items-center gap-1 shadow-sm"
                title="Esporta i dati in formato CSV per Excel"
             >
                <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
                </svg>
                CSV
             </button>
             <button 
                onClick={handleExportPDF}
                className="bg-italia-blue text-white hover:bg-blue-700 border border-transparent font-semibold py-1 px-3 rounded text-sm transition-colors flex items-center gap-1 shadow-sm"
                title="Scarica Fac-simile PDF F24EP"
             >
                <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 21h10a2 2 0 002-2V9.414a1 1 0 00-.293-.707l-5.414-5.414A1 1 0 0012.586 3H7a2 2 0 00-2 2v14a2 2 0 002 2z" />
                </svg>
                Esporta PDF
             </button>
             <span className="hidden sm:inline-block text-xs text-gray-400 uppercase tracking-widest font-semibold border border-gray-300 px-2 py-1 rounded">Fac-simile</span>
        </div>
      </div>

      <div className="overflow-x-auto">
        <div className="min-w-[800px] border-2 border-italia-blue dark:border-blue-500">
          {/* Header Row */}
          <div className="grid grid-cols-12 text-xs font-bold text-center bg-blue-50 dark:bg-blue-900/30 border-b border-italia-blue dark:border-blue-500 divide-x divide-italia-blue dark:divide-blue-500 text-italia-dark dark:text-gray-200 uppercase tracking-wider">
            <div className="col-span-1 p-3 flex items-center justify-center">Sezione</div>
            <div className="col-span-2 p-3 flex items-center justify-center">Codice Tributo</div>
            <div className="col-span-1 p-3 flex items-center justify-center">Codice</div>
            <div className="col-span-3 p-3 flex items-center justify-center">Estremi identificativi</div>
            <div className="col-span-2 p-3 flex items-center justify-center">Riferimento A</div>
            <div className="col-span-1 p-3 flex items-center justify-center">Riferimento B</div>
            <div className="col-span-2 p-3 flex items-center justify-center">Importi a debito versati</div>
          </div>

          {/* 1. Tax Rows (Individual) */}
          {rows.map((row) => {
            const result = results.find(r => r.rowId === row.id);
            if (!result) return null;

            return (
              <div key={row.id} className="grid grid-cols-12 text-sm text-center border-b border-gray-300 dark:border-gray-600 divide-x divide-gray-300 dark:divide-gray-600 hover:bg-gray-50 dark:hover:bg-gray-700/50 bg-white dark:bg-gray-800">
                <div className="col-span-1 p-2 font-mono font-semibold text-gray-900 dark:text-gray-100 flex items-center justify-center text-[10px] sm:text-xs">
                    {row.section}
                </div>
                <div className="col-span-2 p-2 font-mono font-bold text-gray-800 dark:text-gray-100">{row.taxCode}</div>
                <div className="col-span-1 p-2 font-mono font-bold text-gray-800 dark:text-gray-100">{row.locationCode}</div>
                <div className="col-span-3 p-2 font-mono text-xs text-left truncate px-2 text-gray-700 dark:text-gray-300" title={row.description}>
                  {row.description}
                  <div className="text-[10px] text-gray-400 dark:text-gray-500 mt-0.5 flex items-center gap-1">
                    <span>(Incl. interessi € {result.legalInterest.toFixed(2)})</span>
                    {result.legalInterest > 0 && result.legalInterest < 1.03 && (
                      <span className="text-orange-600 dark:text-orange-400 bg-orange-50 dark:bg-orange-900/30 px-1 rounded border border-orange-200 dark:border-orange-800" title="L'interesse può non essere dovuto in quanto inferiore al minimale (€ 1,03)">
                        ⚠️ &lt; Min
                      </span>
                    )}
                  </div>
                </div>
                <div className="col-span-2 p-2 font-mono text-gray-900 dark:text-gray-100">{row.referenceMonth} {row.referenceYear}</div>
                <div className="col-span-1 p-2 font-mono text-gray-900 dark:text-gray-100">{row.referenceYear}</div>
                <div className="col-span-2 p-2 font-mono font-bold text-right pr-4 text-italia-blue dark:text-blue-400">
                  {formatCurrency(result.totalTaxWithInterest)}
                </div>
              </div>
            );
          })}

          {/* 2. Aggregated Sanction Rows */}
          {sanctionRows.map((sanction, index) => (
            <div key={`sanction-${index}`} className="grid grid-cols-12 text-sm text-center border-b border-gray-300 dark:border-gray-600 divide-x divide-gray-300 dark:divide-gray-600 bg-gray-50/50 dark:bg-gray-700/30">
              <div className="col-span-1 p-2 font-mono font-semibold text-gray-900 dark:text-gray-100 flex items-center justify-center text-[10px] sm:text-xs">
                {sanction.section}
              </div>
              <div className="col-span-2 p-2 font-mono font-bold text-gray-800 dark:text-gray-100">{sanction.code}</div>
              <div className="col-span-1 p-2 font-mono font-bold text-gray-800 dark:text-gray-100">{sanction.locationCode}</div>
              <div className="col-span-3 p-2 font-mono text-xs text-left truncate px-2 italic text-gray-500 dark:text-gray-400">
                {sanction.description}
              </div>
              <div className="col-span-2 p-2 font-mono text-gray-900 dark:text-gray-100">
                {/* For aggregated sanctions, usually Ref A matches the year or is left blank if months differ. We show the month of the first entry for context or just the year. */}
                {sanction.referenceMonth} {sanction.referenceYear}
              </div>
              <div className="col-span-1 p-2 font-mono text-gray-900 dark:text-gray-100">{sanction.referenceYear}</div>
              <div className="col-span-2 p-2 font-mono font-bold text-right pr-4 text-red-700 dark:text-red-400">
                {formatCurrency(sanction.amount)}
              </div>
            </div>
          ))}

          {/* Total Row */}
           <div className="grid grid-cols-12 text-sm text-center bg-blue-50 dark:bg-blue-900/30 font-bold text-gray-800 dark:text-gray-200">
            <div className="col-span-10 p-3 text-right text-base">TOTALE GENERALE</div>
            <div className="col-span-2 p-3 text-right pr-4 text-base">
              {formatCurrency(results.reduce((acc, curr) => acc + curr.totalTaxWithInterest + curr.totalSanction, 0))}
            </div>
          </div>
        </div>
      </div>

      <div className="mt-6 text-xs text-gray-500 dark:text-gray-400 space-y-1">
        <p>* Importi arrotondati alla seconda cifra decimale come da standard F24.</p>
        <p>** <span className="font-semibold text-italia-blue dark:text-blue-400">Importo Codice Tributo</span>: Comprende l'imposta originaria + interessi legali maturati (visualizzati nel dettaglio).</p>
        <p>*** Calcolo Sanzioni aggiornato alla Riforma D.Lgs 87/2024 (Base 12.5% entro 90gg / 25% oltre).</p>
        <p>**** Le sanzioni con stesso codice e anno di riferimento sono aggregate in un'unica riga.</p>
      </div>
    </div>
  );
};

export default F24Preview;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import Header from './components/Header';
import Footer from './components/Footer';
import F24Preview from './components/F24Preview';
import { TAX_CODES, REGION_CODES } from './constants';
import { F24Row, CalculationResult, InterestPeriod } from './types';
import { calculateRow, formatCurrency } from './utils/calculation';

function App() {
  const [originalDueDate, setOriginalDueDate] = useState<string>(new Date().toISOString().split('T')[0]);
  const [ravvedimentoDate, setRavvedimentoDate] = useState<string>(new Date().toISOString().split('T')[0]);

  const [rows, setRows] = useState<F24Row[]>([]);

  // New Row State
  const [selectedTaxCode, setSelectedTaxCode] = useState<string>(TAX_CODES[0].code);
  const [amount, setAmount] = useState<string>('');
  const [refMonth, setRefMonth] = useState<string>('01');
  const [refYear, setRefYear] = useState<string>(new Date().getFullYear().toString());
  const [locationCode, setLocationCode] = useState<string>('');

  // UI State
  const [darkMode, setDarkMode] = useState(false);
  const [showRegionTooltip, setShowRegionTooltip] = useState(false);
  const regionTooltipRef = useRef<HTMLDivElement>(null);

  // Modal State
  const [interestModalOpen, setInterestModalOpen] = useState(false);
  const [selectedInterestDetails, setSelectedInterestDetails] = useState<{code: string, amount: number, details: InterestPeriod[]} | null>(null);

  useEffect(() => {
    const stored = localStorage.getItem('color-theme');
    if (stored === 'dark' || (!stored && window.matchMedia('(prefers-color-scheme: dark)').matches)) {
      setDarkMode(true);
    } else {
      setDarkMode(false);
    }
  }, []);

  useEffect(() => {
    if (darkMode) {
      document.documentElement.classList.add('dark');
      localStorage.setItem('color-theme', 'dark');
    } else {
      document.documentElement.classList.remove('dark');
      localStorage.setItem('color-theme', 'light');
    }
  }, [darkMode]);

  // Handle clicking outside the tooltip to close it
  useEffect(() => {
    function handleClickOutside(event: MouseEvent) {
      if (regionTooltipRef.current && !regionTooltipRef.current.contains(event.target as Node)) {
        setShowRegionTooltip(false);
      }
    }
    document.addEventListener("mousedown", handleClickOutside);
    return () => {
      document.removeEventListener("mousedown", handleClickOutside);
    };
  }, [regionTooltipRef]);

  // Reset location code when tax code changes
  useEffect(() => {
    setLocationCode('');
    setShowRegionTooltip(false);
  }, [selectedTaxCode]);

  const toggleDarkMode = () => setDarkMode(!darkMode);

  const selectedTaxInfo = useMemo(() => TAX_CODES.find(t => t.code === selectedTaxCode), [selectedTaxCode]);
  const isRegionCodeField = selectedTaxInfo?.requiresLocationCode && selectedTaxInfo?.locationCodeLabel?.toLowerCase().includes('regione');

  const handleAddRow = () => {
    if (!amount || isNaN(parseFloat(amount))) return;
    if (selectedTaxInfo?.requiresLocationCode && !locationCode) {
      alert(`Il campo "${selectedTaxInfo.locationCodeLabel}" è obbligatorio per questo codice tributo.`);
      return;
    }

    const newRow: F24Row = {
      id: Math.random().toString(36).substr(2, 9),
      taxCode: selectedTaxCode,
      description: selectedTaxInfo?.description || '',
      originalAmount: parseFloat(amount),
      referenceMonth: refMonth,
      referenceYear: refYear,
      section: selectedTaxInfo?.section || 'ERARIO',
      locationCode: locationCode.toUpperCase()
    };

    setRows([...rows, newRow]);
    setAmount('');
    setLocationCode('');
  };

  const handleRemoveRow = (id: string) => {
    setRows(rows.filter(r => r.id !== id));
  };

  const openInterestModal = (code: string, originalAmount: number, details: InterestPeriod[]) => {
    setSelectedInterestDetails({
      code,
      amount: originalAmount,
      details
    });
    setInterestModalOpen(true);
  };

  const closeInterestModal = () => {
    setInterestModalOpen(false);
    setSelectedInterestDetails(null);
  };

  const results: CalculationResult[] = useMemo(() => {
    return rows.map(row => calculateRow(row, originalDueDate, ravvedimentoDate));
  }, [rows, originalDueDate, ravvedimentoDate]);

  return (
    <>
      <Header darkMode={darkMode} toggleDarkMode={toggleDarkMode} />

      <main className="flex-grow max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-10 space-y-8 w-full relative">

        {/* Info Banner (Chapter 5.2 - Transparency) */}
        <div className="bg-blue-50 dark:bg-blue-900/20 border-l-4 border-italia-blue p-4 rounded-r shadow-sm">
          <div className="flex">
            <div className="flex-shrink-0">
              <svg className="h-5 w-5 text-italia-blue" viewBox="0 0 20 20" fill="currentColor">
                <path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7-4a1 1 0 11-2 0 1 1 0 012 0zM9 9a1 1 0 000 2v3a1 1 0 001 1h1a1 1 0 100-2v-3a1 1 0 00-1-1H9z" clipRule="evenodd" />
              </svg>
            </div>
            <div className="ml-3">
              <p className="text-sm text-blue-900 dark:text-blue-100">
                <strong>Nota Informativa:</strong> Questo strumento supporta il calcolo del ravvedimento operoso secondo la normativa vigente (inclusa Riforma D.Lgs 87/2024). I calcoli sono da intendersi come supporto operativo e non sostituiscono le verifiche ufficiali.
              </p>
            </div>
          </div>
        </div>

        {/* Settings Card */}
        <section className="bg-white dark:bg-gray-800 rounded shadow-md border-t-4 border-italia-blue p-6 transition-colors duration-200">
          <h2 className="text-xl font-bold text-italia-dark dark:text-white mb-6 border-b border-gray-200 dark:border-gray-700 pb-2">
            1. Date di Riferimento
          </h2>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            <div>
              <label className="block text-sm font-semibold text-gray-700 dark:text-gray-300 mb-2">Scadenza Originaria</label>
              <input 
                type="date" 
                value={originalDueDate}
                onChange={(e) => setOriginalDueDate(e.target.value)}
                className="w-full rounded border-2 border-gray-300 dark:border-gray-600 dark:bg-gray-700 dark:text-white shadow-sm focus:border-italia-blue focus:ring-0 sm:text-base p-2.5 transition-colors"
              />
            </div>
            <div>
              <label className="block text-sm font-semibold text-gray-700 dark:text-gray-300 mb-2">Data Ravvedimento (Pagamento)</label>
              <input 
                type="date" 
                value={ravvedimentoDate}
                onChange={(e) => setRavvedimentoDate(e.target.value)}
                className="w-full rounded border-2 border-gray-300 dark:border-gray-600 dark:bg-gray-700 dark:text-white shadow-sm focus:border-italia-blue focus:ring-0 sm:text-base p-2.5 transition-colors"
              />
            </div>
          </div>
        </section>

        {/* Input Card */}
        <section className="bg-white dark:bg-gray-800 rounded shadow-md border-t-4 border-italia-blue p-6 transition-colors duration-200">
           <h2 className="text-xl font-bold text-italia-dark dark:text-white mb-6 border-b border-gray-200 dark:border-gray-700 pb-2">
            2. Inserimento Tributi
          </h2>

          <div className="grid grid-cols-1 md:grid-cols-12 gap-6 items-end">
            <div className="md:col-span-4">
              <label className="block text-sm font-semibold text-gray-700 dark:text-gray-300 mb-2">Codice Tributo</label>
              <select 
                value={selectedTaxCode}
                onChange={(e) => setSelectedTaxCode(e.target.value)}
                className="w-full rounded border-2 border-gray-300 dark:border-gray-600 dark:bg-gray-700 dark:text-white shadow-sm focus:border-italia-blue focus:ring-0 sm:text-base p-2.5 transition-colors"
              >
                {TAX_CODES.map(code => (
                  <option key={code.code} value={code.code}>{code.code} - {code.description}</option>
                ))}
              </select>
            </div>

            {/* Conditional Input for Region/Municipality Code */}
            {selectedTaxInfo?.requiresLocationCode ? (
              <div className="md:col-span-2 relative" ref={regionTooltipRef}>
                <div className="flex items-center gap-2 mb-2">
                  <label className="block text-sm font-semibold text-gray-700 dark:text-gray-300 truncate" title={selectedTaxInfo.locationCodeLabel}>
                    {selectedTaxInfo.locationCodeLabel}
                  </label>
                  {isRegionCodeField && (
                    <button
                      type="button"
                      onClick={() => setShowRegionTooltip(!showRegionTooltip)}
                      className="text-italia-blue dark:text-blue-400 hover:text-blue-600 focus:outline-none"
                      title="Elenco Codici Regioni"
                    >
                      <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                        <path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7-4a1 1 0 11-2 0 1 1 0 012 0zM9 9a1 1 0 000 2v3a1 1 0 001 1h1a1 1 0 100-2v-3a1 1 0 00-1-1H9z" clipRule="evenodd" />
                      </svg>
                    </button>
                  )}
                </div>

                <input 
                  type="text"
                  value={locationCode}
                  onChange={(e) => setLocationCode(e.target.value)}
                  maxLength={selectedTaxInfo.locationCodeMaxLength}
                  className="w-full rounded border-2 border-orange-300 dark:border-orange-500 dark:bg-gray-700 dark:text-white shadow-sm focus:border-italia-blue focus:ring-0 sm:text-base p-2.5 transition-colors uppercase"
                  placeholder={selectedTaxInfo.locationCodeMaxLength === 2 ? "es. 09" : "es. H501"}
                />

                {/* Region Codes Tooltip */}
                {showRegionTooltip && isRegionCodeField && (
                  <div className="absolute z-20 left-0 mt-1 w-64 p-2 bg-white dark:bg-gray-700 border border-gray-200 dark:border-gray-600 rounded-md shadow-xl text-xs max-h-60 overflow-y-auto">
                    <div className="grid grid-cols-4 gap-x-2 gap-y-1 p-1">
                      {REGION_CODES.map((region) => (
                        <React.Fragment key={region.code}>
                          <button 
                             onClick={() => { setLocationCode(region.code); setShowRegionTooltip(false); }}
                             className="col-span-1 font-mono font-bold text-italia-blue dark:text-blue-300 hover:bg-gray-100 dark:hover:bg-gray-600 rounded text-center"
                          >
                            {region.code}
                          </button>
                          <div className="col-span-3 text-gray-700 dark:text-gray-200 truncate" title={region.name}>{region.name}</div>
                        </React.Fragment>
                      ))}
                    </div>
                  </div>
                )}
              </div>
            ) : (
              // Spacer to keep layout consistent if no code needed
              <div className="md:col-span-2"></div> 
            )}

            <div className="md:col-span-1">
              <label className="block text-sm font-semibold text-gray-700 dark:text-gray-300 mb-2">Mese</label>
              <select 
                value={refMonth}
                onChange={(e) => setRefMonth(e.target.value)}
                className="w-full rounded border-2 border-gray-300 dark:border-gray-600 dark:bg-gray-700 dark:text-white shadow-sm focus:border-italia-blue focus:ring-0 sm:text-base p-2.5 transition-colors"
              >
                {Array.from({length: 12}, (_, i) => String(i + 1).padStart(2, '0')).map(m => (
                  <option key={m} value={m}>{m}</option>
                ))}
              </select>
