export interface InterestPeriod {
  startDate: string;
  endDate: string;
  rate: number;
  days: number;
  amount: number;
}

export interface CalculationResult {
  rowId: string;
  daysLate: number;
  legalInterest: number;
  interestDetails: InterestPeriod[]; // Detailed breakdown
  sanctionAmount: number;
  sanctionPercentage: number;
  sanctionFormula: string;      // Description of the formula used
  totalTaxWithInterest: number; // For F24EP Tax Code column
  totalSanction: number;        // For F24EP Sanction Code column
  ravvedimentoType: string;
}

export enum RavvedimentoType {
  SPRINT = "Sprint (fino a 14 gg)",
  BREVE = "Breve (15-30 gg)",
  INTERMEDIO = "Intermedio (31-90 gg)",
  LUNGO = "Lungo (entro dichiarazione anno succ.)",
  LUNGHISSIMO = "Lunghissimo (entro 2 anni)",
  OLTRE = "Oltre 2 anni"
}

import { LEGAL_INTEREST_RATES, TAX_CODES } from '../constants';
import { CalculationResult, F24Row, RavvedimentoType, InterestPeriod } from '../types';

export const parseDate = (dateStr: string): Date => {
  return new Date(dateStr);
};

export const getDaysDiff = (start: Date, end: Date): number => {
  const diffTime = end.getTime() - start.getTime();
  return Math.ceil(diffTime / (1000 * 60 * 60 * 24));
};

export const calculateLegalInterest = (amount: number, dueDate: Date, payDate: Date): { total: number, details: InterestPeriod[] } => {
  let totalInterest = 0;
  const details: InterestPeriod[] = [];

  // Interest starts accruing from the day AFTER the due date
  const accrualStart = new Date(dueDate);
  accrualStart.setDate(accrualStart.getDate() + 1);

  const accrualEnd = new Date(payDate);

  // If paid on or before due date (plus 1 day adjustment logic), no interest
  if (accrualStart > accrualEnd) {
    return { total: 0, details: [] };
  }

  // Iterate through defined legal rates to find intersections with the accrual period
  const sortedRates = [...LEGAL_INTEREST_RATES].sort((a, b) => new Date(a.start).getTime() - new Date(b.start).getTime());

  for (const rateObj of sortedRates) {
    const rateStart = new Date(rateObj.start);
    const rateEnd = new Date(rateObj.end);

    // Determine the overlap between [RateStart, RateEnd] and [AccrualStart, AccrualEnd]
    // Max of Starts
    const periodStart = rateStart > accrualStart ? rateStart : accrualStart;
    // Min of Ends
    const periodEnd = rateEnd < accrualEnd ? rateEnd : accrualEnd;

    // Check if there is a valid overlap
    if (periodStart <= periodEnd) {
      // Calculate days in this period (Inclusive)
      const timeDiff = periodEnd.getTime() - periodStart.getTime();
      const days = Math.floor(timeDiff / (1000 * 3600 * 24)) + 1;

      if (days > 0) {
        // Interest Formula: Amount * Rate * Days / 36500
        const periodInterest = (amount * rateObj.rate * days) / 36500;

        totalInterest += periodInterest;

        details.push({
          startDate: periodStart.toISOString().split('T')[0],
          endDate: periodEnd.toISOString().split('T')[0],
          rate: rateObj.rate,
          days: days,
          amount: periodInterest
        });
      }
    }
  }

  return { total: totalInterest, details };
};

export const calculateSanction = (amount: number, daysLate: number, violationDate: Date, payDate: Date): { percentage: number, amount: number, type: string, formula: string } => {
  // Riforma Sanzioni (D.Lgs 87/2024) applies to violations committed AFTER 01/09/2024.
  // Art. 5 D.Lgs 87/2024: "Le disposizioni... si applicano alle violazioni commesse a partire dal 1° settembre 2024."
  const reformDate = new Date('2024-09-01');
  const isPostReform = violationDate >= reformDate;

  // Base Rates
  const baseRate = isPostReform ? 25.0 : 30.0;
  const minRate = isPostReform ? 12.5 : 15.0; // Reduced base for delays <= 90 days (Art 13 c.1 lett a-bis new)

  // Deadlines for "Lungo" and "Lunghissimo" (approximate declaration deadlines)
  // "Lungo" (lett. b): By the presentation of the declaration for the year of violation (Year X -> submitted Nov X+1)
  const violationYear = violationDate.getFullYear();
  // Standard deadline usually 30/11 of following year
  const declarationDeadlineLungo = new Date(violationYear + 1, 10, 30); // 30 Nov Year+1

  // "Lunghissimo" (lett. b-bis): By the presentation of the declaration for the subsequent year (Year X -> submitted Nov X+2)
  const declarationDeadlineLunghissimo = new Date(violationYear + 2, 10, 30); // 30 Nov Year+2

  let percentage = 0;
  let type = '';
  let formula = '';

  if (daysLate <= 14) {
    // Ravvedimento Sprint
    // Pre-Reform: 0.1% per day (1/10 of 15% / 15 days is approx logic, usually cited as 0.1% fixed or 1/15 of Breve)
    // Post-Reform: 1/15 of Breve. Breve is 1/10 of 12.5%.
    if (isPostReform) {
        const breveRate = minRate / 10; // 1.25%
        percentage = (breveRate / 15) * daysLate; // ~0.0833% per day
        formula = `1/15 di Ravv. Breve (1/10 di ${minRate}%) per giorno`;
    } else {
        percentage = 0.1 * daysLate;
        formula = `0,1% per ogni giorno di ritardo`;
    }
    type = RavvedimentoType.SPRINT;

  } else if (daysLate <= 30) {
    // Ravvedimento Breve (Art. 13 c. 1 lett. a)
    // 1/10 of Minimum
    percentage = minRate / 10;
    formula = `1/10 del Minimo (${minRate}%)`;
    type = RavvedimentoType.BREVE;

  } else if (daysLate <= 90) {
    // Ravvedimento Intermedio (Art. 13 c. 1 lett. a-bis)
    // 1/9 of Minimum
    percentage = minRate / 9;
    formula = `1/9 del Minimo (${minRate}%)`;
    type = RavvedimentoType.INTERMEDIO;

  } else if (payDate <= declarationDeadlineLungo) {
    // Ravvedimento Lungo (Art. 13 c. 1 lett. b)
    // 1/8 of Base
    percentage = baseRate / 8;
    formula = `1/8 del Base (${baseRate}%)`;
    type = RavvedimentoType.LUNGO;

  } else if (payDate <= declarationDeadlineLunghissimo) {
    // Ravvedimento Lunghissimo (Art. 13 c. 1 lett. b-bis)
    // 1/7 of Base
    percentage = baseRate / 7;
    formula = `1/7 del Base (${baseRate}%)`;
    type = RavvedimentoType.LUNGHISSIMO;

  } else {
    // Oltre 2 anni (Art. 13 c. 1 lett. b-ter)
    // 1/6 of Base
    percentage = baseRate / 6;
    formula = `1/6 del Base (${baseRate}%)`;
    type = RavvedimentoType.OLTRE;
  }

  return {
    percentage: percentage,
    amount: (amount * percentage) / 100,
    type: type,
    formula: formula
  };
};

export const calculateRow = (row: F24Row, dueDateStr: string, payDateStr: string): CalculationResult => {
  const dueDate = parseDate(dueDateStr);
  const payDate = parseDate(payDateStr);

  const daysLate = getDaysDiff(dueDate, payDate);

  if (daysLate <= 0) {
    return {
      rowId: row.id,
      daysLate: 0,
      legalInterest: 0,
      interestDetails: [],
      sanctionAmount: 0,
      sanctionPercentage: 0,
      sanctionFormula: 'Nessuna sanzione',
      totalTaxWithInterest: row.originalAmount,
      totalSanction: 0,
      ravvedimentoType: 'In tempo'
    };
  }

  const interestData = calculateLegalInterest(row.originalAmount, dueDate, payDate);
  const sanction = calculateSanction(row.originalAmount, daysLate, dueDate, payDate);

  return {
    rowId: row.id,
    daysLate: daysLate,
    legalInterest: interestData.total,
    interestDetails: interestData.details,
    sanctionAmount: sanction.amount,
    sanctionPercentage: sanction.percentage,
    sanctionFormula: sanction.formula,
    // F24EP Specific: Tax Code Amount = Original + Interest (Principio del Cumulo)
    totalTaxWithInterest: row.originalAmount + interestData.total,
    totalSanction: sanction.amount,
    ravvedimentoType: sanction.type
  };
};

export const formatCurrency = (val: number) => {
  return new Intl.NumberFormat('it-IT', { style: 'currency', currency: 'EUR' }).format(val);
};

export const getSanctionCode = (taxCode: string): string => {
  const found = TAX_CODES.find(t => t.code === taxCode);
  return found ? found.sanctionCode : '89xx';
};

import React, { useState, useEffect, useMemo, useRef } from 'react';
import Header from './components/Header';
import Footer from './components/Footer';
import F24Preview from './components/F24Preview';
import { TAX_CODES, REGION_CODES } from './constants';
import { F24Row, CalculationResult, InterestPeriod } from './types';
import { calculateRow, formatCurrency } from './utils/calculation';

function App() {
  const [originalDueDate, setOriginalDueDate] = useState<string>(new Date().toISOString().split('T')[0]);
  const [ravvedimentoDate, setRavvedimentoDate] = useState<string>(new Date().toISOString().split('T')[0]);

  const [rows, setRows] = useState<F24Row[]>([]);

  // New Row State
  const [selectedTaxCode, setSelectedTaxCode] = useState<string>(TAX_CODES[0].code);
  const [amount, setAmount] = useState<string>('');
  const [refMonth, setRefMonth] = useState<string>('01');
  const [refYear, setRefYear] = useState<string>(new Date().getFullYear().toString());
  const [locationCode, setLocationCode] = useState<string>('');

  // UI State
  const [darkMode, setDarkMode] = useState(false);
  const [showRegionTooltip, setShowRegionTooltip] = useState(false);
  const regionTooltipRef = useRef<HTMLDivElement>(null);

  // Modal State
  const [interestModalOpen, setInterestModalOpen] = useState(false);
  const [selectedInterestDetails, setSelectedInterestDetails] = useState<{code: string, amount: number, details: InterestPeriod[]} | null>(null);

  useEffect(() => {
    const stored = localStorage.getItem('color-theme');
    if (stored === 'dark' || (!stored && window.matchMedia('(prefers-color-scheme: dark)').matches)) {
      setDarkMode(true);
    } else {
      setDarkMode(false);
    }
  }, []);

  useEffect(() => {
    if (darkMode) {
      document.documentElement.classList.add('dark');
      localStorage.setItem('color-theme', 'dark');
    } else {
      document.documentElement.classList.remove('dark');
      localStorage.setItem('color-theme', 'light');
    }
  }, [darkMode]);

  // Handle clicking outside the tooltip to close it
  useEffect(() => {
    function handleClickOutside(event: MouseEvent) {
      if (regionTooltipRef.current && !regionTooltipRef.current.contains(event.target as Node)) {
        setShowRegionTooltip(false);
      }
    }
    document.addEventListener("mousedown", handleClickOutside);
    return () => {
      document.removeEventListener("mousedown", handleClickOutside);
    };
  }, [regionTooltipRef]);

  // Reset location code when tax code changes
  useEffect(() => {
    setLocationCode('');
    setShowRegionTooltip(false);
  }, [selectedTaxCode]);

  const toggleDarkMode = () => setDarkMode(!darkMode);

  const selectedTaxInfo = useMemo(() => TAX_CODES.find(t => t.code === selectedTaxCode), [selectedTaxCode]);
  const isRegionCodeField = selectedTaxInfo?.requiresLocationCode && selectedTaxInfo?.locationCodeLabel?.toLowerCase().includes('regione');

  const handleAddRow = () => {
    if (!amount || isNaN(parseFloat(amount))) return;
    if (selectedTaxInfo?.requiresLocationCode && !locationCode) {
      alert(`Il campo "${selectedTaxInfo.locationCodeLabel}" è obbligatorio per questo codice tributo.`);
      return;
    }

    const newRow: F24Row = {
      id: Math.random().toString(36).substr(2, 9),
      taxCode: selectedTaxCode,
      description: selectedTaxInfo?.description || '',
      originalAmount: parseFloat(amount),
      referenceMonth: refMonth,
      referenceYear: refYear,
      section: selectedTaxInfo?.section || 'ERARIO',
      locationCode: locationCode.toUpperCase()
    };

    setRows([...rows, newRow]);
    setAmount('');
    setLocationCode('');
  };

  const handleRemoveRow = (id: string) => {
    setRows(rows.filter(r => r.id !== id));
  };

  const openInterestModal = (code: string, originalAmount: number, details: InterestPeriod[]) => {
    setSelectedInterestDetails({
      code,
      amount: originalAmount,
      details
    });
    setInterestModalOpen(true);
  };

  const closeInterestModal = () => {
    setInterestModalOpen(false);
    setSelectedInterestDetails(null);
  };

  const results: CalculationResult[] = useMemo(() => {
    return rows.map(row => calculateRow(row, originalDueDate, ravvedimentoDate));
  }, [rows, originalDueDate, ravvedimentoDate]);

  return (
    <>
      <Header darkMode={darkMode} toggleDarkMode={toggleDarkMode} />

      <main className="flex-grow max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-10 space-y-8 w-full relative">

        {/* Info Banner (Chapter 5.2 - Transparency) */}
        <div className="bg-blue-50 dark:bg-blue-900/20 border-l-4 border-italia-blue p-4 rounded-r shadow-sm">
          <div className="flex">
            <div className="flex-shrink-0">
              <svg className="h-5 w-5 text-italia-blue" viewBox="0 0 20 20" fill="currentColor">
                <path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7-4a1 1 0 11-2 0 1 1 0 012 0zM9 9a1 1 0 000 2v3a1 1 0 001 1h1a1 1 0 100-2v-3a1 1 0 00-1-1H9z" clipRule="evenodd" />
              </svg>
            </div>
            <div className="ml-3">
              <p className="text-sm text-blue-900 dark:text-blue-100">
                <strong>Nota Informativa:</strong> Questo strumento supporta il calcolo del ravvedimento operoso secondo la normativa vigente (inclusa Riforma D.Lgs 87/2024). I calcoli sono da intendersi come supporto operativo e non sostituiscono le verifiche ufficiali.
              </p>
            </div>
          </div>
        </div>

        {/* Settings Card */}
        <section className="bg-white dark:bg-gray-800 rounded shadow-md border-t-4 border-italia-blue p-6 transition-colors duration-200">
          <h2 className="text-xl font-bold text-italia-dark dark:text-white mb-6 border-b border-gray-200 dark:border-gray-700 pb-2">
            1. Date di Riferimento
          </h2>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            <div>
              <label className="block text-sm font-semibold text-gray-700 dark:text-gray-300 mb-2">Scadenza Originaria</label>
              <input 
                type="date" 
                value={originalDueDate}
                onChange={(e) => setOriginalDueDate(e.target.value)}
                className="w-full rounded border-2 border-gray-300 dark:border-gray-600 dark:bg-gray-700 dark:text-white shadow-sm focus:border-italia-blue focus:ring-0 sm:text-base p-2.5 transition-colors"
              />
            </div>
            <div>
              <label className="block text-sm font-semibold text-gray-700 dark:text-gray-300 mb-2">Data Ravvedimento (Pagamento)</label>
              <input 
                type="date" 
                value={ravvedimentoDate}
                onChange={(e) => setRavvedimentoDate(e.target.value)}
                className="w-full rounded border-2 border-gray-300 dark:border-gray-600 dark:bg-gray-700 dark:text-white shadow-sm focus:border-italia-blue focus:ring-0 sm:text-base p-2.5 transition-colors"
              />
            </div>
          </div>
        </section>

        {/* Input Card */}
        <section className="bg-white dark:bg-gray-800 rounded shadow-md border-t-4 border-italia-blue p-6 transition-colors duration-200">
           <h2 className="text-xl font-bold text-italia-dark dark:text-white mb-6 border-b border-gray-200 dark:border-gray-700 pb-2">
            2. Inserimento Tributi
          </h2>

          <div className="grid grid-cols-1 md:grid-cols-12 gap-6 items-end">
            <div className="md:col-span-4">
              <label className="block text-sm font-semibold text-gray-700 dark:text-gray-300 mb-2">Codice Tributo</label>
              <select 
                value={selectedTaxCode}
                onChange={(e) => setSelectedTaxCode(e.target.value)}
                className="w-full rounded border-2 border-gray-300 dark:border-gray-600 dark:bg-gray-700 dark:text-white shadow-sm focus:border-italia-blue focus:ring-0 sm:text-base p-2.5 transition-colors"
              >
                {TAX_CODES.map(code => (
                  <option key={code.code} value={code.code}>{code.code} - {code.description}</option>
                ))}
              </select>
            </div>

            {/* Conditional Input for Region/Municipality Code */}
            {selectedTaxInfo?.requiresLocationCode ? (
              <div className="md:col-span-2 relative" ref={regionTooltipRef}>
                <div className="flex items-center gap-2 mb-2">
                  <label className="block text-sm font-semibold text-gray-700 dark:text-gray-300 truncate" title={selectedTaxInfo.locationCodeLabel}>
                    {selectedTaxInfo.locationCodeLabel}
                  </label>
                  {isRegionCodeField && (
                    <button
                      type="button"
                      onClick={() => setShowRegionTooltip(!showRegionTooltip)}
                      className="text-italia-blue dark:text-blue-400 hover:text-blue-600 focus:outline-none"
                      title="Elenco Codici Regioni"
                    >
                      <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                        <path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7-4a1 1 0 11-2 0 1 1 0 012 0zM9 9a1 1 0 000 2v3a1 1 0 001 1h1a1 1 0 100-2v-3a1 1 0 00-1-1H9z" clipRule="evenodd" />
                      </svg>
                    </button>
                  )}
                </div>

                <input 
                  type="text"
                  value={locationCode}
                  onChange={(e) => setLocationCode(e.target.value)}
                  maxLength={selectedTaxInfo.locationCodeMaxLength}
                  className="w-full rounded border-2 border-orange-300 dark:border-orange-500 dark:bg-gray-700 dark:text-white shadow-sm focus:border-italia-blue focus:ring-0 sm:text-base p-2.5 transition-colors uppercase"
                  placeholder={selectedTaxInfo.locationCodeMaxLength === 2 ? "es. 09" : "es. H501"}
