import * as pdfjsLib from 'pdfjs-dist';
import { F24Row, TaxCode } from '../types';
import { TAX_CODES } from '../constants';

// Set worker source for PDF.js (required for browser environment)
// Using the same version as in the import map
pdfjsLib.GlobalWorkerOptions.workerSrc = 'https://esm.sh/pdfjs-dist@3.11.174/build/pdf.worker.min.js';

interface ExtractedData {
  taxCode: string;
  year: string;
  amount: number;
  month?: string;
  locationCode?: string;
}

/**
 * Parses an F24EP PDF file and attempts to extract tax rows.
 * This uses a heuristic approach: it scans text items for known Tax Codes,
 * then looks in the vicinity for Years and Amounts.
 */
export const parseF24PDF = async (file: File): Promise<F24Row[]> => {
  const arrayBuffer = await file.arrayBuffer();
  const pdf = await pdfjsLib.getDocument({ data: arrayBuffer }).promise;
  const extractedRows: F24Row[] = [];

  // Iterate through all pages
  for (let pageNum = 1; pageNum <= pdf.numPages; pageNum++) {
    const page = await pdf.getPage(pageNum);
    const textContent = await page.getTextContent();

    // Flatten text items into a single array of strings for simpler scanning
    // Filter out empty strings
    const items = textContent.items
      .map((item: any) => item.str.trim())
      .filter((str: string) => str.length > 0);

    // Heuristic scan
    for (let i = 0; i < items.length; i++) {
      const currentItem = items[i].toUpperCase();

      // 1. Detect Tax Code
      // Check if current item matches a known tax code (exact match)
      const matchedTax = TAX_CODES.find(t => t.code === currentItem);

      if (matchedTax) {
        // Found a potential row start. Now look ahead in the next ~15 items for Year and Amount.
        // F24 structure usually puts amounts to the right (later in the array).

        let foundYear = '';
        let foundAmount = 0;
        let foundLocation = '';

        // Scan window (look ahead)
        const scanLimit = Math.min(items.length, i + 15);

        for (let j = i + 1; j < scanLimit; j++) {
          const item = items[j];

          // Detect Year: 4 digits starting with 20
          if (!foundYear && /^20[0-9]{2}$/.test(item)) {
            foundYear = item;
            continue;
          }

          // Detect Amount: Digits with comma or dot (e.g. 1.200,50 or 1200,50)
          // We look for a string that looks like currency but isn't a year
          // Regex allows dots/commas, must end with digit.
          if (foundAmount === 0 && /^[0-9]{1,3}(?:\.?[0-9]{3})*(?:,[0-9]{2})$/.test(item)) {
             // Italian format: 1.000,00 -> convert to 1000.00
             const normalized = item.replace(/\./g, '').replace(',', '.');
             const val = parseFloat(normalized);
             if (!isNaN(val)) {
               foundAmount = val;
             }
             continue;
          }

          // Detect Location Code (if required)
          // Heuristic: 2 chars (Region) or 4 chars (Municipality) depending on tax code requirement
          if (matchedTax.requiresLocationCode && !foundLocation) {
             const maxLen = matchedTax.locationCodeMaxLength || 4;
             // Basic check: alphanumeric, matches length constraint approx
             if (item.length >= 2 && item.length <= maxLen && /^[A-Z0-9]+$/i.test(item)) {
                // Avoid capturing the tax code itself or the year
                if (item !== matchedTax.code && !/^20[0-9]{2}$/.test(item)) {
                    foundLocation = item.toUpperCase();
                }
             }
          }
        }

        // If we found at least an Amount and a Year (usually mandatory), we create a row
        // If year is missing but amount is found, default to current year? No, stricter is better.
        if (foundAmount > 0) {
            extractedRows.push({
                id: Math.random().toString(36).substr(2, 9),
                taxCode: matchedTax.code,
                description: matchedTax.description,
                originalAmount: foundAmount,
                referenceMonth: '01', // Month is hard to parse reliably from text soup, default to 01
                referenceYear: foundYear || new Date().getFullYear().toString(),
                section: matchedTax.section,
                locationCode: foundLocation
            });
        }
      }
    }
  }

  return extractedRows;
};

import React, { useState, useEffect, useMemo, useRef } from 'react';
import Header from './components/Header';
import Footer from './components/Footer';
import F24Preview from './components/F24Preview';
import { TAX_CODES, REGION_CODES } from './constants';
import { F24Row, CalculationResult, InterestPeriod } from './types';
import { calculateRow, formatCurrency } from './utils/calculation';
import { parseF24PDF } from './utils/pdfParser';

function App() {
  const [originalDueDate, setOriginalDueDate] = useState<string>(new Date().toISOString().split('T')[0]);
  const [ravvedimentoDate, setRavvedimentoDate] = useState<string>(new Date().toISOString().split('T')[0]);

  const [rows, setRows] = useState<F24Row[]>([]);

  // New Row State
  const [selectedTaxCode, setSelectedTaxCode] = useState<string>(TAX_CODES[0].code);
  const [amount, setAmount] = useState<string>('');
  const [refMonth, setRefMonth] = useState<string>('01');
  const [refYear, setRefYear] = useState<string>(new Date().getFullYear().toString());
  const [locationCode, setLocationCode] = useState<string>('');

  // UI State
  const [darkMode, setDarkMode] = useState(false);
  const [showRegionTooltip, setShowRegionTooltip] = useState(false);
  const [isUploading, setIsUploading] = useState(false);
  const regionTooltipRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Modal State
  const [interestModalOpen, setInterestModalOpen] = useState(false);
  const [selectedInterestDetails, setSelectedInterestDetails] = useState<{code: string, amount: number, details: InterestPeriod[]} | null>(null);

  useEffect(() => {
    const stored = localStorage.getItem('color-theme');
    if (stored === 'dark' || (!stored && window.matchMedia('(prefers-color-scheme: dark)').matches)) {
      setDarkMode(true);
    } else {
      setDarkMode(false);
    }
  }, []);

  useEffect(() => {
    if (darkMode) {
      document.documentElement.classList.add('dark');
      localStorage.setItem('color-theme', 'dark');
    } else {
      document.documentElement.classList.remove('dark');
      localStorage.setItem('color-theme', 'light');
    }
  }, [darkMode]);

  // Handle clicking outside the tooltip to close it
  useEffect(() => {
    function handleClickOutside(event: MouseEvent) {
      if (regionTooltipRef.current && !regionTooltipRef.current.contains(event.target as Node)) {
        setShowRegionTooltip(false);
      }
    }
    document.addEventListener("mousedown", handleClickOutside);
    return () => {
      document.removeEventListener("mousedown", handleClickOutside);
    };
  }, [regionTooltipRef]);

  // Reset location code when tax code changes
  useEffect(() => {
    setLocationCode('');
    setShowRegionTooltip(false);
  }, [selectedTaxCode]);

  const toggleDarkMode = () => setDarkMode(!darkMode);

  const selectedTaxInfo = useMemo(() => TAX_CODES.find(t => t.code === selectedTaxCode), [selectedTaxCode]);
  const isRegionCodeField = selectedTaxInfo?.requiresLocationCode && selectedTaxInfo?.locationCodeLabel?.toLowerCase().includes('regione');

  const handleAddRow = () => {
    if (!amount || isNaN(parseFloat(amount))) return;
    if (selectedTaxInfo?.requiresLocationCode && !locationCode) {
      alert(`Il campo "${selectedTaxInfo.locationCodeLabel}" è obbligatorio per questo codice tributo.`);
      return;
    }

    const newRow: F24Row = {
      id: Math.random().toString(36).substr(2, 9),
      taxCode: selectedTaxCode,
      description: selectedTaxInfo?.description || '',
      originalAmount: parseFloat(amount),
      referenceMonth: refMonth,
      referenceYear: refYear,
      section: selectedTaxInfo?.section || 'ERARIO',
      locationCode: locationCode.toUpperCase()
    };

    setRows([...rows, newRow]);
    setAmount('');
    setLocationCode('');
  };

  const handleRemoveRow = (id: string) => {
    setRows(rows.filter(r => r.id !== id));
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    if (file.type !== 'application/pdf') {
      alert('Per favore carica un file PDF valido.');
      return;
    }

    setIsUploading(true);
    try {
      const extractedRows = await parseF24PDF(file);
      if (extractedRows.length === 0) {
        alert('Nessun dato compatibile trovato nel PDF. Assicurati che sia un F24EP digitale (non scansionato).');
      } else {
        setRows(prev => [...prev, ...extractedRows]);
        // Update Ref Year automatically if found to help manual entry
        if (extractedRows[0].referenceYear) {
            setRefYear(extractedRows[0].referenceYear);
        }
      }
    } catch (error) {
      console.error('PDF Parse Error', error);
      alert('Errore durante la lettura del file PDF. Riprova con un altro file.');
    } finally {
      setIsUploading(false);
      // Reset input
      if (fileInputRef.current) fileInputRef.current.value = '';
    }
  };

  const openInterestModal = (code: string, originalAmount: number, details: InterestPeriod[]) => {
    setSelectedInterestDetails({
      code,
      amount: originalAmount,
      details
    });
    setInterestModalOpen(true);
  };

  const closeInterestModal = () => {
    setInterestModalOpen(false);
    setSelectedInterestDetails(null);
  };

  const results: CalculationResult[] = useMemo(() => {
    return rows.map(row => calculateRow(row, originalDueDate, ravvedimentoDate));
  }, [rows, originalDueDate, ravvedimentoDate]);

  return (
    <>
      <Header darkMode={darkMode} toggleDarkMode={toggleDarkMode} />

      <main className="flex-grow max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-10 space-y-8 w-full relative">

        {/* Info Banner (Chapter 5.2 - Transparency) */}
        <div className="bg-blue-50 dark:bg-blue-900/20 border-l-4 border-italia-blue p-4 rounded-r shadow-sm">
          <div className="flex">
            <div className="flex-shrink-0">
              <svg className="h-5 w-5 text-italia-blue" viewBox="0 0 20 20" fill="currentColor">
                <path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7-4a1 1 0 11-2 0 1 1 0 012 0zM9 9a1 1 0 000 2v3a1 1 0 001 1h1a1 1 0 100-2v-3a1 1 0 00-1-1H9z" clipRule="evenodd" />
              </svg>
            </div>
            <div className="ml-3">
              <p className="text-sm text-blue-900 dark:text-blue-100">
                <strong>Nota Informativa:</strong> Questo strumento supporta il calcolo del ravvedimento operoso secondo la normativa vigente (inclusa Riforma D.Lgs 87/2024). I calcoli sono da intendersi come supporto operativo e non sostituiscono le verifiche ufficiali.
              </p>
            </div>
          </div>
        </div>

        {/* Settings Card */}
        <section className="bg-white dark:bg-gray-800 rounded shadow-md border-t-4 border-italia-blue p-6 transition-colors duration-200">
          <h2 className="text-xl font-bold text-italia-dark dark:text-white mb-6 border-b border-gray-200 dark:border-gray-700 pb-2">
            1. Date di Riferimento
          </h2>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            <div>
              <label className="block text-sm font-semibold text-gray-700 dark:text-gray-300 mb-2">Scadenza Originaria</label>
              <input 
                type="date" 
                value={originalDueDate}
                onChange={(e) => setOriginalDueDate(e.target.value)}
                className="w-full rounded border-2 border-gray-300 dark:border-gray-600 dark:bg-gray-700 dark:text-white shadow-sm focus:border-italia-blue focus:ring-0 sm:text-base p-2.5 transition-colors"
              />
            </div>
            <div>
              <label className="block text-sm font-semibold text-gray-700 dark:text-gray-300 mb-2">Data Ravvedimento (Pagamento)</label>
              <input 
                type="date" 
                value={ravvedimentoDate}
                onChange={(e) => setRavvedimentoDate(e.target.value)}
                className="w-full rounded border-2 border-gray-300 dark:border-gray-600 dark:bg-gray-700 dark:text-white shadow-sm focus:border-italia-blue focus:ring-0 sm:text-base p-2.5 transition-colors"
              />
            </div>
          </div>
        </section>

        {/* Input Card */}
        <section className="bg-white dark:bg-gray-800 rounded shadow-md border-t-4 border-italia-blue p-6 transition-colors duration-200">
           <div className="flex justify-between items-center mb-6 border-b border-gray-200 dark:border-gray-700 pb-2">
             <h2 className="text-xl font-bold text-italia-dark dark:text-white">
              2. Inserimento Tributi
             </h2>
             <div>
               <input 
                 type="file" 
                 ref={fileInputRef}
                 accept="application/pdf" 
                 className="hidden" 
                 onChange={handleFileUpload}
               />
               <button 
                onClick={() => fileInputRef.current?.click()}
                disabled={isUploading}
                className="flex items-center gap-2 bg-white dark:bg-gray-700 border border-gray-300 dark:border-gray-600 text-italia-blue dark:text-blue-300 hover:bg-gray-50 dark:hover:bg-gray-600 px-3 py-1.5 rounded text-sm font-semibold shadow-sm transition-all"
               >
                 {isUploading ? (
                   <svg className="animate-spin h-4 w-4 text-italia-blue" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                     <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                     <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                   </svg>
                 ) : (
                   <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-8l-4-4m0 0L8 8m4-4v12" />
                   </svg>
                 )}
                 {isUploading ? 'Analisi PDF...' : 'Carica F24 (PDF)'}
               </button>
             </div>
           </div>

          <div className="grid grid-cols-1 md:grid-cols-12 gap-6 items-end">
            <div className="md:col-span-4">
              <label className="block text-sm font-semibold text-gray-700 dark:text-gray-300 mb-2">Codice Tributo</label>
              <select 
                value={selectedTaxCode}
                onChange={(e) => setSelectedTaxCode(e.target.value)}
                className="w-full rounded border-2 border-gray-300 dark:border-gray-600 dark:bg-gray-700 dark:text-white shadow-sm focus:border-italia-blue focus:ring-0 sm:text-base p-2.5 transition-colors"
              >
                {TAX_CODES.map(code => (
                  <option key={code.code} value={code.code}>{code.code} - {code.description}</option>
                ))}
              </select>
            </div>

            {/* Conditional Input for Region/Municipality Code */}
            {selectedTaxInfo?.requiresLocationCode ? (
              <div className="md:col-span-2 relative" ref={regionTooltipRef}>
                <div className="flex items-center gap-2 mb-2">
                  <label className="block text-sm font-semibold text-gray-700 dark:text-gray-300 truncate" title={selectedTaxInfo.locationCodeLabel}>
                    {selectedTaxInfo.locationCodeLabel}
                  </label>
                  {isRegionCodeField && (
                    <button
                      type="button"
                      onClick={() => setShowRegionTooltip(!showRegionTooltip)}
                      className="text-italia-blue dark:text-blue-400 hover:text-blue-600 focus:outline-none"
                      title="Elenco Codici Regioni"
                    >
                      <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                        <path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7-4a1 1 0 11-2 0 1 1 0 012 0zM9 9a1 1 0 000 2v3a1 1 0 001 1h1a1 1 0 100-2v-3a1 1 0 00-1-1H9z" clipRule="evenodd" />
                      </svg>
                    </button>
                  )}
                </div>

                <input 
                  type="text"
                  value={locationCode}
                  onChange={(e) => setLocationCode(e.target.value)}
                  maxLength={selectedTaxInfo.locationCodeMaxLength}
                  className="w-full rounded border-2 border-orange-300 dark:border-orange-500 dark:bg-gray-700 dark:text-white shadow-sm focus:border-italia-blue focus:ring-0 sm:text-base p-2.5 transition-colors uppercase"
                  placeholder={selectedTaxInfo.locationCodeMaxLength === 2 ? "es. 09" : "es. H501"}
                />

                {/* Region Codes Tooltip */}
                {showRegionTooltip && isRegionCodeField && (
                  <div className="absolute z-20 left-0 mt-1 w-64 p-2 bg-white dark:bg-gray-700 border border-gray-200 dark:border-gray-600 rounded-md shadow-xl text-xs max-h-60 overflow-y-auto">
                    <div className="grid grid-cols-4 gap-x-2 gap-y-1 p-1">
                      {REGION_CODES.map((region) => (
                        <React.Fragment key={region.code}>
                          <button 
                             onClick={() => { setLocationCode(region.code); setShowRegionTooltip(false); }}
                             className="col-span-1 font-mono font-bold text-italia-blue dark:text-blue-300 hover:bg-gray-100 dark:hover:bg-gray-600 rounded text-center"
                          >
                            {region.code}
                          </button>
                          <div className="col-span-3 text-gray-700 dark:text-gray-200 truncate" title={region.name}>{region.name}</div>
                        </React.Fragment>
                      ))}
                    </div>
                  </div>
                )}
