import * as pdfjsLib from 'pdfjs-dist';
import { F24Row, TaxCode } from '../types';
import { TAX_CODES } from '../constants';

// Set worker source for PDF.js (required for browser environment)
// Handle potential ESM default export mismatch (common with pdfjs-dist via CDNs like esm.sh)
const pdfjs = (pdfjsLib as any).default || pdfjsLib;

if (pdfjs.GlobalWorkerOptions) {
    // Using the same version as in the import map
    pdfjs.GlobalWorkerOptions.workerSrc = 'https://esm.sh/pdfjs-dist@3.11.174/build/pdf.worker.min.js';
} else {
    console.error('PDF.js GlobalWorkerOptions not found. Check import structure.');
}

interface ExtractedData {
  taxCode: string;
  year: string;
  amount: number;
  month?: string;
  locationCode?: string;
}

/**
 * Parses an F24EP PDF file and attempts to extract tax rows.
 * This uses a heuristic approach: it scans text items for known Tax Codes,
 * then looks in the vicinity for Years and Amounts.
 */
export const parseF24PDF = async (file: File): Promise<F24Row[]> => {
  const arrayBuffer = await file.arrayBuffer();

  // Use the resolved pdfjs object (with fallback)
  const loadingTask = pdfjs.getDocument({ data: arrayBuffer });
  const pdf = await loadingTask.promise;

  const extractedRows: F24Row[] = [];

  // Iterate through all pages
  for (let pageNum = 1; pageNum <= pdf.numPages; pageNum++) {
    const page = await pdf.getPage(pageNum);
    const textContent = await page.getTextContent();

    // Flatten text items into a single array of strings for simpler scanning
    // Filter out empty strings
    const items = textContent.items
      .map((item: any) => item.str.trim())
      .filter((str: string) => str.length > 0);

    // Heuristic scan
    for (let i = 0; i < items.length; i++) {
      const currentItem = items[i].toUpperCase();

      // 1. Detect Tax Code
      // Check if current item matches a known tax code (exact match)
      const matchedTax = TAX_CODES.find(t => t.code === currentItem);

      if (matchedTax) {
        // Found a potential row start. Now look ahead in the next ~15 items for Year and Amount.
        // F24 structure usually puts amounts to the right (later in the array).

        let foundYear = '';
        let foundAmount = 0;
        let foundLocation = '';

        // Scan window (look ahead)
        const scanLimit = Math.min(items.length, i + 15);

        for (let j = i + 1; j < scanLimit; j++) {
          const item = items[j];

          // Detect Year: 4 digits starting with 20
          if (!foundYear && /^20[0-9]{2}$/.test(item)) {
            foundYear = item;
            continue;
          }

          // Detect Amount: Digits with comma or dot (e.g. 1.200,50 or 1200,50)
          // We look for a string that looks like currency but isn't a year
          // Regex allows dots/commas, must end with digit.
          if (foundAmount === 0 && /^[0-9]{1,3}(?:\.?[0-9]{3})*(?:,[0-9]{2})$/.test(item)) {
             // Italian format: 1.000,00 -> convert to 1000.00
             const normalized = item.replace(/\./g, '').replace(',', '.');
             const val = parseFloat(normalized);
             if (!isNaN(val)) {
               foundAmount = val;
             }
             continue;
          }

          // Detect Location Code (if required)
          // Heuristic: 2 chars (Region) or 4 chars (Municipality) depending on tax code requirement
          if (matchedTax.requiresLocationCode && !foundLocation) {
             const maxLen = matchedTax.locationCodeMaxLength || 4;
             // Basic check: alphanumeric, matches length constraint approx
             if (item.length >= 2 && item.length <= maxLen && /^[A-Z0-9]+$/i.test(item)) {
                // Avoid capturing the tax code itself or the year
                if (item !== matchedTax.code && !/^20[0-9]{2}$/.test(item)) {
                    foundLocation = item.toUpperCase();
                }
             }
          }
        }

        // If we found at least an Amount and a Year (usually mandatory), we create a row
        // If year is missing but amount is found, default to current year? No, stricter is better.
        if (foundAmount > 0) {
            extractedRows.push({
                id: Math.random().toString(36).substr(2, 9),
                taxCode: matchedTax.code,
                description: matchedTax.description,
                originalAmount: foundAmount,
                referenceMonth: '01', // Month is hard to parse reliably from text soup, default to 01
                referenceYear: foundYear || new Date().getFullYear().toString(),
                section: matchedTax.section,
                locationCode: foundLocation
            });
        }
      }
    }
  }

  return extractedRows;
};

