                       disabled={pageNumber >= numPages}
                       onClick={() => setPageNumber(p => p + 1)}
                       className="px-2 py-1 rounded hover:bg-gray-200 dark:hover:bg-gray-700 disabled:opacity-50"
                     >
                       &gt;
                     </button>
                   </div>
                 )}
                 <button onClick={() => setShowPreview(false)} className="text-gray-400 hover:text-gray-600 dark:hover:text-gray-300 transition-colors">
                  <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                  </svg>
                </button>
              </div>
            </div>
            <div className="flex-grow bg-gray-200 dark:bg-gray-900 overflow-auto flex justify-center p-4">
               <canvas ref={canvasRef} className="shadow-lg max-w-full" />
            </div>
            <div className="px-6 py-4 border-t border-gray-200 dark:border-gray-700 bg-gray-50 dark:bg-gray-900 rounded-b-lg flex justify-end gap-3">
               <button 
                onClick={() => setShowPreview(false)}
                className="bg-gray-200 dark:bg-gray-700 text-gray-800 dark:text-gray-200 px-4 py-2 rounded text-sm font-semibold hover:bg-gray-300 dark:hover:bg-gray-600 transition-colors"
              >
                Chiudi
              </button>
              <button 
                onClick={handleExportPDF}
                className="bg-italia-blue text-white px-4 py-2 rounded text-sm font-semibold hover:bg-blue-700 transition-colors shadow-sm"
              >
                Scarica PDF
              </button>
            </div>
          </div>
        </div>
      )}
    </>
  );
};

export default F24Preview;

